var QUESTIONS_THEORY_5 = [
{type:"mcq",diff:"easy",en:{q:"What is the full form of DOS in the context of computer operating systems?",opts:["Disk Operating System","Data Operating System","Device Operating System","Digital Operating System"],ans:0,exp:"DOS stands for Disk Operating System. It is a family of disk-based operating systems that heavily rely on command-line interfaces where users must type specific text commands to interact with the computer hardware. MS-DOS, developed by Microsoft, was the most widely used version before graphical environments like Windows became the dominant industry standard."},hi:{q:"कंप्यूटर ऑपरेटिंग सिस्टम के संदर्भ में DOS का पूर्ण रूप क्या है?",opts:["डिस्क ऑपरेटिंग सिस्टम (Disk Operating System)","डेटा ऑपरेटिंग सिस्टम (Data Operating System)","डिवाइस ऑपरेटिंग सिस्टम (Device Operating System)","डिजिटल ऑपरेटिंग सिस्टम (Digital Operating System)"],ans:0,exp:"DOS का अर्थ डिस्क ऑपरेटिंग सिस्टम है। यह एक कमांड-लाइन आधारित ऑपरेटिंग सिस्टम है जहां उपयोगकर्ताओं को कंप्यूटर हार्डवेयर के साथ बातचीत करने के लिए विशिष्ट टेक्स्ट कमांड टाइप करना पड़ता है। Microsoft द्वारा विकसित MS-DOS, ग्राफिकल वातावरण (Windows) मानक बनने से पहले सबसे व्यापक रूप से उपयोग किया जाने वाला संस्करण था।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following terms describes an interface where users interact with the system entirely by typing text commands?",opts:["GUI (Graphical User Interface)","CLI (Command Line Interface)","API (Application Programming Interface)","VUI (Voice User Interface)"],ans:1,exp:"A Command Line Interface (CLI) is a text-based user interface used to view and manage computer files and execute programs. Unlike a GUI which uses a mouse, windows, and icons, a CLI requires the user to memorize and input syntactically correct text commands, which is exactly how DOS and the Linux terminal operate."},hi:{q:"निम्नलिखित में से कौन सा शब्द उस इंटरफ़ेस का वर्णन करता है जहाँ उपयोगकर्ता पूरी तरह से टेक्स्ट कमांड टाइप करके सिस्टम के साथ बातचीत करते हैं?",opts:["GUI (ग्राफिकल यूजर इंटरफेस)","CLI (कमांड लाइन इंटरफेस)","API (एप्लीकेशन प्रोग्रामिंग इंटरफेस)","VUI (वॉयस यूजर इंटरफेस)"],ans:1,exp:"कमांड लाइन इंटरफ़ेस (CLI) एक टेक्स्ट-आधारित उपयोगकर्ता इंटरफ़ेस है जिसका उपयोग कंप्यूटर फ़ाइलों को प्रबंधित करने और प्रोग्राम निष्पादित करने के लिए किया जाता है। माउस और आइकन का उपयोग करने वाले GUI के विपरीत, CLI में उपयोगकर्ता को टेक्स्ट कमांड याद रखने और टाइप करने की आवश्यकता होती है, जैसे कि DOS और Linux टर्मिनल।"}},
{type:"mcq",diff:"easy",en:{q:"Which core DOS system file fundamentally acts as the command interpreter, processing the internal commands typed by the user?",opts:["IO.SYS","MSDOS.SYS","COMMAND.COM","CONFIG.SYS"],ans:2,exp:"COMMAND.COM is the essential command interpreter file in MS-DOS and Windows 9x systems. It serves as the primary user interface, displaying the command prompt and waiting for user input. Furthermore, it contains the executable code for all fundamental internal DOS commands (like DIR, COPY, and DEL) directly within its structure."},hi:{q:"कौन सी मुख्य DOS सिस्टम फ़ाइल मौलिक रूप से कमांड इंटरप्रेटर के रूप में कार्य करती है, जो उपयोगकर्ता द्वारा टाइप किए गए आंतरिक कमांड को संसाधित करती है?",opts:["IO.SYS","MSDOS.SYS","COMMAND.COM","CONFIG.SYS"],ans:2,exp:"COMMAND.COM एमएस-डॉस और विंडोज 9x सिस्टम में आवश्यक कमांड इंटरप्रेटर फ़ाइल है। यह प्राथमिक उपयोगकर्ता इंटरफ़ेस के रूप में कार्य करता है, कमांड प्रॉम्प्ट प्रदर्शित करता है। इसके अलावा, इसमें सभी मूलभूत आंतरिक DOS कमांड (जैसे DIR, COPY, और DEL) के लिए सीधे इसके संरचना के भीतर निष्पादन योग्य कोड होता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which DOS command is utilized to display a complete list of files and subdirectories contained within a specific directory?",opts:["LIST","SHOW","DIR","VIEW"],ans:2,exp:"The 'DIR' (Directory) command is a fundamental internal DOS command used to list the contents of a directory. By default, executing DIR provides the names, extensions, file sizes in bytes, and the date and time each file or folder was last modified, along with a summary of total free disk space."},hi:{q:"एक विशिष्ट निर्देशिका (directory) के भीतर निहित फ़ाइलों और उप-निर्देशिकाओं की पूरी सूची प्रदर्शित करने के लिए किस DOS कमांड का उपयोग किया जाता है?",opts:["LIST","SHOW","DIR","VIEW"],ans:2,exp:"'DIR' (Directory) एक मूलभूत आंतरिक DOS कमांड है जिसका उपयोग निर्देशिका की सामग्री को सूचीबद्ध करने के लिए किया जाता है। डिफ़ॉल्ट रूप से, यह फ़ाइलों के नाम, एक्सटेंशन, आकार और अंतिम संशोधन की तिथि और समय के साथ-साथ कुल खाली डिस्क स्थान का सारांश प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which internal DOS command is executed to completely clear the terminal screen of all previous output and commands?",opts:["CLEAR","CLS","CLEAN","ERASE"],ans:1,exp:"The 'CLS' (Clear Screen) command is a built-in internal DOS command. When executed, it mathematically clears the entire console window of all previously entered commands, text, and error messages, placing the command prompt back at the very top-left corner of a blank screen, which greatly improves readability."},hi:{q:"पिछले सभी आउटपुट और कमांड के टर्मिनल स्क्रीन को पूरी तरह से साफ़ करने के लिए कौन सा आंतरिक DOS कमांड निष्पादित किया जाता है?",opts:["CLEAR","CLS","CLEAN","ERASE"],ans:1,exp:"'CLS' (Clear Screen) कमांड एक इन-बिल्ट आंतरिक DOS कमांड है। निष्पादित होने पर, यह पहले दर्ज किए गए सभी कमांड, टेक्स्ट और त्रुटि संदेशों की पूरी कंसोल विंडो को साफ़ कर देता है, और कमांड प्रॉम्प्ट को वापस स्क्रीन के ऊपर-बाएँ कोने पर रख देता है।"}},
{type:"mcq",diff:"easy",en:{q:"In DOS, what command is specifically used to create a brand new subdirectory?",opts:["MD","CD","RD","NEW"],ans:0,exp:"The 'MD' (Make Directory) command, or alternatively 'MKDIR', is an internal DOS command used to create a new, empty directory (folder) within the current working directory or at a specifically designated path. This allows users to build organized, hierarchical file structures logically on their storage drives."},hi:{q:"DOS में, बिल्कुल नई उप-निर्देशिका (subdirectory) बनाने के लिए विशेष रूप से किस कमांड का उपयोग किया जाता है?",opts:["MD","CD","RD","NEW"],ans:0,exp:"'MD' (Make Directory) कमांड, या 'MKDIR', एक आंतरिक DOS कमांड है जिसका उपयोग वर्तमान कार्यशील निर्देशिका के भीतर या एक निर्दिष्ट पथ पर एक नया, खाली फ़ोल्डर बनाने के लिए किया जाता है। यह उपयोगकर्ताओं को अपने स्टोरेज ड्राइव पर संगठित फ़ाइल संरचनाएं बनाने की अनुमति देता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which DOS command allows a user to navigate from the current directory into a different directory?",opts:["MOVE","JUMP","CD","GOTO"],ans:2,exp:"The 'CD' (Change Directory) command, or 'CHDIR', is the standard command used to switch the current working directory in the command-line environment. By typing 'CD' followed by a valid directory path, the OS updates its environmental context to execute subsequent commands within that new specified folder location."},hi:{q:"कौन सा DOS कमांड उपयोगकर्ता को वर्तमान निर्देशिका से किसी भिन्न निर्देशिका में नेविगेट करने की अनुमति देता है?",opts:["MOVE","JUMP","CD","GOTO"],ans:2,exp:"'CD' (Change Directory) या 'CHDIR', कमांड-लाइन वातावरण में वर्तमान कार्यशील निर्देशिका को बदलने के लिए उपयोग किया जाने वाला मानक कमांड है। 'CD' टाइप करके और एक वैध पथ देकर, OS अपना संदर्भ अपडेट करता है ताकि बाद के कमांड उस नए फ़ोल्डर में निष्पादित हो सकें।"}},
{type:"mcq",diff:"easy",en:{q:"To completely remove an empty directory from the disk in DOS, which command must be used?",opts:["DEL","RD","ERASE","REMOVE"],ans:1,exp:"The 'RD' (Remove Directory) command, or 'RMDIR', is explicitly used to delete a directory. As a strict safety mechanism in basic DOS, the RD command will mathematically fail and return an error if the targeted directory still contains hidden files, normal files, or other nested subdirectories."},hi:{q:"DOS में डिस्क से एक खाली निर्देशिका को पूरी तरह से हटाने के लिए किस कमांड का उपयोग किया जाना चाहिए?",opts:["DEL","RD","ERASE","REMOVE"],ans:1,exp:"'RD' (Remove Directory) या 'RMDIR' कमांड का उपयोग स्पष्ट रूप से किसी निर्देशिका को हटाने के लिए किया जाता है। बेसिक DOS में एक सुरक्षा तंत्र के रूप में, यदि लक्षित निर्देशिका में अभी भी कोई छिपी हुई फ़ाइलें, सामान्य फ़ाइलें या उप-निर्देशिकाएं हैं, तो RD कमांड विफल हो जाएगा।"}},
{type:"mcq",diff:"easy",en:{q:"Which command is utilized in the DOS environment to display the raw text contents of a file directly onto the screen?",opts:["READ","SHOW","TYPE","PRINT"],ans:2,exp:"The 'TYPE' command is an internal DOS command that strictly reads the raw contents of a specified file and prints them sequentially to the standard output (the screen). It is extremely useful for quickly viewing the contents of readable ASCII text files, like .txt or .bat files, without needing a dedicated text editor application."},hi:{q:"DOS वातावरण में किसी फ़ाइल की कच्ची टेक्स्ट सामग्री को सीधे स्क्रीन पर प्रदर्शित करने के लिए किस कमांड का उपयोग किया जाता है?",opts:["READ","SHOW","TYPE","PRINT"],ans:2,exp:"'TYPE' कमांड एक आंतरिक DOS कमांड है जो निर्दिष्ट फ़ाइल की सामग्री को पढ़ता है और उन्हें सीधे स्क्रीन पर प्रिंट करता है। यह .txt या .bat फ़ाइलों जैसे पठनीय ASCII टेक्स्ट फ़ाइलों की सामग्री को जल्दी से देखने के लिए अत्यंत उपयोगी है।"}},
{type:"mcq",diff:"easy",en:{q:"What command is used to duplicate one or more files from a source location to a specified destination in DOS?",opts:["MOVE","COPY","DUPE","CLONE"],ans:1,exp:"The 'COPY' command is a fundamental internal DOS command explicitly engineered to duplicate files. The user specifies the source file path and the target destination path. While excellent for individual files, standard COPY lacks the advanced capabilities of XCOPY, such as recursively copying nested subdirectories and retaining file ownership metadata."},hi:{q:"DOS में किसी स्रोत स्थान से निर्दिष्ट गंतव्य तक एक या अधिक फ़ाइलों की प्रतिलिपि (duplicate) बनाने के लिए किस कमांड का उपयोग किया जाता है?",opts:["MOVE","COPY","DUPE","CLONE"],ans:1,exp:"'COPY' कमांड एक मौलिक आंतरिक DOS कमांड है जिसे स्पष्ट रूप से फ़ाइलों की प्रतिलिपि बनाने के लिए बनाया गया है। उपयोगकर्ता स्रोत फ़ाइल पथ और लक्ष्य गंतव्य निर्दिष्ट करता है। हालाँकि, मानक COPY में XCOPY जैसी उन्नत क्षमताओं का अभाव है, जैसे उप-निर्देशिकाओं की प्रतिलिपि बनाना।"}},
{type:"mcq",diff:"easy",en:{q:"Which command allows a DOS user to change the name of an existing file without modifying its physical contents?",opts:["CHNAME","REN","MOD","CHANGE"],ans:1,exp:"The 'REN' (Rename) command, also accessible as 'RENAME', alters the filename and/or extension of an existing file. This command strictly alters the metadata stored in the directory table; it mathematically performs zero alterations to the actual underlying binary payload or the physical location of the file on the hard disk."},hi:{q:"कौन सा कमांड DOS उपयोगकर्ता को किसी मौजूदा फ़ाइल की भौतिक सामग्री को संशोधित किए बिना उसका नाम बदलने की अनुमति देता है?",opts:["CHNAME","REN","MOD","CHANGE"],ans:1,exp:"'REN' (Rename) कमांड किसी मौजूदा फ़ाइल के फ़ाइल नाम या एक्सटेंशन को बदल देता है। यह कमांड निर्देशिका तालिका (directory table) में संग्रहीत मेटाडेटा को बदलता है; यह वास्तविक अंतर्निहित बाइनरी डेटा या हार्ड डिस्क पर फ़ाइल के भौतिक स्थान में शून्य परिवर्तन करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which basic DOS command is strictly designated for permanently removing files from the storage drive?",opts:["RD","RMDIR","DEL","WIPE"],ans:2,exp:"The 'DEL' (Delete) command, or 'ERASE', is used to permanently remove specific files from the disk. Unlike modern Windows which utilizes a GUI Recycle Bin for easy recovery, a file deleted via the DOS DEL command has its address table pointer removed immediately, marking the disk space as free to be actively overwritten."},hi:{q:"भंडारण ड्राइव से फ़ाइलों को स्थायी रूप से हटाने के लिए कड़ाई से कौन सा मूल DOS कमांड नामित किया गया है?",opts:["RD","RMDIR","DEL","WIPE"],ans:2,exp:"'DEL' (Delete) या 'ERASE' कमांड का उपयोग डिस्क से विशिष्ट फ़ाइलों को स्थायी रूप से हटाने के लिए किया जाता है। आधुनिक विंडोज के विपरीत जो रिकवरी के लिए रिसाइकिल बिन का उपयोग करता है, DOS DEL कमांड के माध्यम से हटाई गई फ़ाइल का एड्रेस टेबल पॉइंटर तुरंत हटा दिया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What characterizes Linux as an Operating System compared to proprietary systems like Windows?",opts:["It is exclusively designed for mobile phones","It is a strictly closed-source, paid software","It is an open-source, Unix-like operating system kernel","It does not support Command Line Interfaces"],ans:2,exp:"Linux is fundamentally a free, open-source, Unix-like operating system kernel originally created by Linus Torvalds. Unlike proprietary software (e.g., Windows), its core source code is publicly accessible, allowing developers worldwide to freely study, modify, mathematically enhance, and mathematically distribute their own custom versions (distributions)."},hi:{q:"विंडोज जैसे मालिकाना (proprietary) सिस्टम की तुलना में लिनक्स एक ऑपरेटिंग सिस्टम के रूप में क्या विशेषता रखता है?",opts:["यह विशेष रूप से मोबाइल फोन के लिए डिज़ाइन किया गया है","यह एक कड़ाई से क्लोज-सोर्स, सशुल्क (paid) सॉफ्टवेयर है","यह एक ओपन-सोर्स, यूनिक्स (Unix) जैसा ऑपरेटिंग सिस्टम कर्नेल है","यह कमांड लाइन इंटरफेस का समर्थन नहीं करता है"],ans:2,exp:"लिनक्स मौलिक रूप से एक स्वतंत्र, ओपन-सोर्स, यूनिक्स जैसा ऑपरेटिंग सिस्टम कर्नेल है जिसे मूल रूप से लिनस टोरवाल्ड्स द्वारा बनाया गया था। मालिकाना सॉफ्टवेयर के विपरीत, इसका कोर सोर्स कोड सार्वजनिक रूप से सुलभ है, जिससे दुनिया भर के डेवलपर्स इसे स्वतंत्र रूप से संशोधित और वितरित कर सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"In Linux architecture, what specific term refers to the core program that manages the CPU, memory, and physical hardware devices?",opts:["The Shell","The Terminal","The Kernel","The GUI"],ans:2,exp:"The Kernel is the absolute core of the Linux operating system. It operates at the lowest mathematical level, acting as a crucial software bridge between the applications running in user-space and the actual raw physical hardware (CPU, RAM, Disks). It meticulously manages process scheduling, memory allocation, and hardware interrupts."},hi:{q:"लिनक्स आर्किटेक्चर में, कौन सा विशिष्ट शब्द उस मुख्य प्रोग्राम को संदर्भित करता है जो CPU, मेमोरी और भौतिक हार्डवेयर उपकरणों का प्रबंधन करता है?",opts:["द शेल (The Shell)","द टर्मिनल (The Terminal)","द कर्नेल (The Kernel)","द जीयूआई (The GUI)"],ans:2,exp:"कर्नेल (Kernel) लिनक्स ऑपरेटिंग सिस्टम का पूर्ण मूल (core) है। यह निम्नतम स्तर पर कार्य करता है, जो उपयोगकर्ता-स्थान (user-space) में चलने वाले अनुप्रयोगों और वास्तविक कच्चे भौतिक हार्डवेयर (CPU, RAM) के बीच एक महत्वपूर्ण सॉफ़्टवेयर ब्रिज के रूप में कार्य करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What acts as the interface layer in Linux that takes human-readable commands and translates them into machine instructions for the Kernel?",opts:["The Shell","The Bootloader","The BIOS","The File System"],ans:0,exp:"The Shell is the command interpreter layer of the Linux OS. It provides an interface (either CLI or GUI) for the user. When a user types a command (like 'ls' or 'pwd'), the shell mathematically parses the text, checks for valid syntax, and translates the request into complex system calls that the Kernel can natively execute."},hi:{q:"लिनक्स में इंटरफ़ेस परत के रूप में कौन कार्य करता है जो मानव-पठनीय कमांड लेता है और उन्हें कर्नेल के लिए मशीन निर्देशों में अनुवादित करता है?",opts:["द शेल (The Shell)","बूटलोडर","BIOS","फ़ाइल सिस्टम"],ans:0,exp:"शेल (Shell) लिनक्स OS की कमांड इंटरप्रेटर परत है। यह उपयोगकर्ता के लिए एक इंटरफ़ेस प्रदान करता है। जब कोई उपयोगकर्ता कोई कमांड टाइप करता है, तो शेल टेक्स्ट को पार्स करता है, सिंटैक्स की जाँच करता है, और अनुरोध को सिस्टम कॉल में अनुवादित करता है जिसे कर्नेल निष्पादित कर सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Who is the ultimate administrative user in a Linux system, possessing absolute unrestricted privileges over all files and commands?",opts:["admin","superuser","root","sysadmin"],ans:2,exp:"In Linux and Unix-like systems, 'root' is the default username for the superuser. The root account has absolute, unrestricted mathematical power over the entire system. It can modify or delete any critical system file, change permissions for any user, and bind to sensitive network ports, making it both powerful and dangerous if misused."},hi:{q:"लिनक्स सिस्टम में अंतिम प्रशासनिक उपयोगकर्ता कौन है, जिसके पास सभी फ़ाइलों और कमांडों पर पूर्ण अप्रतिबंधित विशेषाधिकार हैं?",opts:["admin","superuser","root (रूट)","sysadmin"],ans:2,exp:"लिनक्स और यूनिक्स जैसे सिस्टम में, 'root' सुपरयूज़र के लिए डिफ़ॉल्ट उपयोगकर्ता नाम है। रूट खाते में संपूर्ण सिस्टम पर पूर्ण, अप्रतिबंधित शक्ति होती है। यह किसी भी महत्वपूर्ण सिस्टम फ़ाइल को संशोधित या हटा सकता है, और किसी भी उपयोगकर्ता के लिए अनुमतियाँ बदल सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which simple Linux command displays the absolute path of the directory you are currently working inside?",opts:["dir","cd","pwd","path"],ans:2,exp:"The 'pwd' (Print Working Directory) command is an essential Linux navigation tool. When executed, it outputs the full, absolute path starting from the root directory ('/') down to the specific folder the user is currently located in, helping users orient themselves within deeply nested directory trees."},hi:{q:"कौन सा सरल लिनक्स कमांड उस निर्देशिका का पूर्ण (absolute) पथ प्रदर्शित करता है जिसके अंदर आप वर्तमान में काम कर रहे हैं?",opts:["dir","cd","pwd","path"],ans:2,exp:"'pwd' (Print Working Directory) कमांड एक आवश्यक लिनक्स नेविगेशन टूल है। निष्पादित होने पर, यह रूट निर्देशिका ('/') से शुरू होकर उस विशिष्ट फ़ोल्डर तक का पूर्ण पथ आउटपुट करता है जिसमें उपयोगकर्ता वर्तमान में स्थित है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the fundamental Linux command used to display the files and folders contained within a directory?",opts:["show","ls","list","dir"],ans:1,exp:"The 'ls' (List) command is the fundamental utility in Linux used to view the contents of a directory. Analogous to the DOS 'DIR' command, 'ls' simply outputs the names of files and subdirectories. Its functionality can be mathematically expanded dramatically by using specific flags, such as '-l' for a detailed list or '-a' to show hidden items."},hi:{q:"किसी निर्देशिका (directory) के भीतर निहित फ़ाइलों और फ़ोल्डरों को प्रदर्शित करने के लिए उपयोग किया जाने वाला मौलिक लिनक्स कमांड क्या है?",opts:["show","ls","list","dir"],ans:1,exp:"'ls' (List) कमांड लिनक्स में निर्देशिका की सामग्री को देखने के लिए उपयोग की जाने वाली मौलिक उपयोगिता है। DOS के 'DIR' कमांड के समान, 'ls' फ़ाइलों और उप-निर्देशिकाओं के नाम आउटपुट करता है। झंडों (flags) का उपयोग करके इसकी कार्यक्षमता बढ़ाई जा सकती है, जैसे '-l' या '-a'।"}},
{type:"mcq",diff:"easy",en:{q:"To navigate upwards to the immediate parent directory in Linux, which specific sequence must follow the 'cd' command?",opts:["cd /","cd \\","cd ..","cd ~"],ans:2,exp:"In Linux file system navigation, '..' mathematically represents the parent directory (one level up), while a single '.' represents the current directory. Therefore, executing 'cd ..' commands the shell to move the user's active context strictly one step backward up the hierarchical directory tree."},hi:{q:"लिनक्स में तत्काल मूल निर्देशिका (parent directory) में ऊपर की ओर नेविगेट करने के लिए, 'cd' कमांड के बाद कौन सा विशिष्ट अनुक्रम होना चाहिए?",opts:["cd /","cd \\","cd ..","cd ~"],ans:2,exp:"लिनक्स फ़ाइल सिस्टम नेविगेशन में, '..' गणितीय रूप से मूल निर्देशिका (एक स्तर ऊपर) का प्रतिनिधित्व करता है, जबकि एक एकल '.' वर्तमान निर्देशिका का प्रतिनिधित्व करता है। इसलिए, 'cd ..' निष्पादित करने से शेल उपयोगकर्ता के सक्रिय संदर्भ को एक कदम पीछे ले जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which command is explicitly used to create a new directory in a Linux environment?",opts:["md","make","mkdir","newdir"],ans:2,exp:"The 'mkdir' (Make Directory) command is the standard Linux utility for creating new folders. A user can create a single directory by passing a name (e.g., 'mkdir Docs'), or utilize specific flags like '-p' to mathematically generate an entire complex path of nested subdirectories simultaneously in one command."},hi:{q:"लिनक्स वातावरण में एक नई निर्देशिका बनाने के लिए स्पष्ट रूप से किस कमांड का उपयोग किया जाता है?",opts:["md","make","mkdir","newdir"],ans:2,exp:"'mkdir' (Make Directory) कमांड नए फ़ोल्डर बनाने के लिए मानक लिनक्स उपयोगिता है। उपयोगकर्ता नाम (जैसे, 'mkdir Docs') पास करके एक निर्देशिका बना सकता है, या एक ही कमांड में नेस्टेड उप-निर्देशिकाओं का पूरा पथ उत्पन्न करने के लिए '-p' जैसे विशिष्ट झंडे का उपयोग कर सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which Linux command physically removes an empty directory from the file system?",opts:["rd","rmdir","deldir","removedir"],ans:1,exp:"The 'rmdir' (Remove Directory) command is strictly utilized to delete directories. As a deliberate fail-safe mechanism to prevent accidental massive data loss, 'rmdir' will mathematically refuse to execute and throw an error if the targeted directory still contains any files or nested folders. It only works on perfectly empty directories."},hi:{q:"कौन सा लिनक्स कमांड फ़ाइल सिस्टम से एक खाली निर्देशिका (empty directory) को भौतिक रूप से हटा देता है?",opts:["rd","rmdir","deldir","removedir"],ans:1,exp:"'rmdir' (Remove Directory) कमांड का उपयोग विशेष रूप से निर्देशिकाओं को हटाने के लिए किया जाता है। आकस्मिक डेटा हानि को रोकने के लिए एक जानबूझकर फेल-सेफ के रूप में, 'rmdir' निष्पादित करने से इनकार कर देगा यदि लक्षित निर्देशिका में कोई फ़ाइलें या फ़ोल्डर हैं। यह केवल खाली निर्देशिकाओं पर काम करता है।"}},
{type:"mcq",diff:"easy",en:{q:"To copy files or directories natively in Linux, which concise command is utilized?",opts:["copy","dup","cp","xcopy"],ans:2,exp:"The 'cp' command is the native Linux utility for copying files and directories. By default, typing 'cp source.txt dest.txt' duplicates a single file. To mathematically copy an entire directory and all its nested contents, the administrator must append the recursive '-r' flag (e.g., 'cp -r /source /dest')."},hi:{q:"लिनक्स में फ़ाइलों या निर्देशिकाओं को कॉपी करने के लिए, किस संक्षिप्त कमांड का उपयोग किया जाता है?",opts:["copy","dup","cp","xcopy"],ans:2,exp:"'cp' कमांड फ़ाइलों और निर्देशिकाओं की प्रतिलिपि बनाने के लिए मूल लिनक्स उपयोगिता है। डिफ़ॉल्ट रूप से, 'cp source.txt dest.txt' टाइप करने से एक फ़ाइल की प्रतिलिपि बन जाती है। एक संपूर्ण निर्देशिका और उसकी सभी सामग्री को कॉपी करने के लिए, '-r' (recursive) ध्वज का उपयोग करना होगा।"}},
{type:"mcq",diff:"easy",en:{q:"Which powerful Linux command serves the dual purpose of moving files to new locations and renaming them?",opts:["move","mv","ren","change"],ans:1,exp:"The 'mv' (Move) command is exceptionally versatile in Linux. It physically alters the file system pointers. If the destination path is a different directory, the file is physically moved there. If the destination is simply a new filename in the exact same directory, the command effectively acts as a rename operation."},hi:{q:"कौन सा शक्तिशाली लिनक्स कमांड फ़ाइलों को नए स्थानों पर ले जाने (move) और उनका नाम बदलने (rename) के दोहरे उद्देश्य को पूरा करता है?",opts:["move","mv","ren","change"],ans:1,exp:"'mv' (Move) कमांड लिनक्स में असाधारण रूप से बहुमुखी है। यह फ़ाइल सिस्टम पॉइंटर्स को भौतिक रूप से बदल देता है। यदि गंतव्य एक अलग निर्देशिका है, तो फ़ाइल को वहाँ ले जाया जाता है। यदि गंतव्य उसी निर्देशिका में एक नया फ़ाइल नाम है, तो यह प्रभावी रूप से नाम बदलने (rename) का कार्य करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which base Linux command is rigorously used to delete files and mathematically unlinks them from the storage drive?",opts:["delete","erase","rm","wipe"],ans:2,exp:"The 'rm' (Remove) command is the strict tool for deleting files in Linux. It fundamentally unlinks the file from the filesystem metadata directory. It must be used with extreme caution because, unlike GUI environments, files deleted with basic 'rm' bypass any trash bin and are instantly irretrievable under standard conditions."},hi:{q:"भंडारण ड्राइव से फ़ाइलों को हटाने और उन्हें गणितीय रूप से अनलिंक करने के लिए किस बेस लिनक्स कमांड का कठोरता से उपयोग किया जाता है?",opts:["delete","erase","rm","wipe"],ans:2,exp:"'rm' (Remove) कमांड लिनक्स में फ़ाइलों को हटाने के लिए एक सख्त उपकरण है। यह मौलिक रूप से फ़ाइल को फ़ाइल सिस्टम मेटाडेटा निर्देशिका से अनलिंक करता है। इसका उपयोग अत्यधिक सावधानी के साथ किया जाना चाहिए क्योंकि इसके द्वारा हटाई गई फ़ाइलें किसी भी ट्रैश बिन को बायपास करती हैं और तुरंत अप्राप्य हो जाती हैं।"}},
{type:"mcq",diff:"easy",en:{q:"If a Linux terminal becomes cluttered with excessive text output, which command instantly restores a clean, blank screen?",opts:["cls","clean","clear","reset"],ans:2,exp:"The 'clear' command is universally used in Linux and Unix terminal environments to wipe the visible screen of previous commands and output, placing the prompt back at the top. Alternatively, users can often press the keyboard shortcut 'Ctrl + L' to achieve the exact same mathematical screen clearing effect instantly."},hi:{q:"यदि लिनक्स टर्मिनल अत्यधिक टेक्स्ट आउटपुट से भर जाता है, तो कौन सा कमांड तुरंत एक साफ, खाली स्क्रीन को पुनर्स्थापित करता है?",opts:["cls","clean","clear","reset"],ans:2,exp:"'clear' कमांड का उपयोग लिनक्स और यूनिक्स टर्मिनल वातावरण में पिछली कमांड और आउटपुट की दृश्यमान स्क्रीन को पोंछने के लिए किया जाता है, जिससे प्रॉम्प्ट वापस शीर्ष पर आ जाता है। वैकल्पिक रूप से, उपयोगकर्ता 'Ctrl + L' कीबोर्ड शॉर्टकट भी दबा सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Who is the principal software engineer globally recognized for writing the original open-source Linux kernel in 1991?",opts:["Bill Gates","Steve Jobs","Dennis Ritchie","Linus Torvalds"],ans:3,exp:"Linus Torvalds, a Finnish software engineering student, authored the very first version of the Linux kernel in 1991. He subsequently released the code for free under the GNU General Public License (GPL), which catalyzed a massive global collaborative effort, leading to the incredibly robust enterprise Linux distributions heavily utilized today."},hi:{q:"1991 में मूल ओपन-सोर्स लिनक्स कर्नेल लिखने के लिए विश्व स्तर पर पहचाने जाने वाले प्रमुख सॉफ्टवेयर इंजीनियर कौन हैं?",opts:["बिल गेट्स","स्टीव जॉब्स","डेनिस रिची","लिनस टोरवाल्ड्स (Linus Torvalds)"],ans:3,exp:"लिनस टोरवाल्ड्स ने 1991 में लिनक्स कर्नेल का पहला संस्करण लिखा था। बाद में उन्होंने GNU जनरल पब्लिक लाइसेंस (GPL) के तहत मुफ्त में कोड जारी किया, जिसने एक विशाल वैश्विक सहयोगात्मक प्रयास को उत्प्रेरित किया, जिससे आज उपयोग किए जाने वाले मजबूत एंटरप्राइज़ लिनक्स वितरण का नेतृत्व हुआ।"}},
{type:"mcq",diff:"easy",en:{q:"In both DOS and Linux environments, which specific wildcard character is mathematically interpreted as representing any combination of zero or multiple unknown characters?",opts:["?","#","%","*"],ans:3,exp:"The asterisk (*) is the most powerful wildcard operator. In command-line parsing logic, it mathematically signifies 'any sequence of characters, including no characters at all'. For example, running 'rm *.txt' explicitly commands the shell to delete every single file ending with the '.txt' extension, regardless of the filename length."},hi:{q:"DOS और Linux दोनों वातावरणों में, किस विशिष्ट वाइल्डकार्ड वर्ण को गणितीय रूप से शून्य या एकाधिक अज्ञात वर्णों के किसी भी संयोजन का प्रतिनिधित्व करने के रूप में व्याख्या किया जाता है?",opts:["?","#","%","*"],ans:3,exp:"तारांकन (*) सबसे शक्तिशाली वाइल्डकार्ड ऑपरेटर है। कमांड-लाइन में, यह गणितीय रूप से 'वर्णों के किसी भी अनुक्रम' को दर्शाता है। उदाहरण के लिए, 'rm *.txt' चलाने से शेल को '.txt' एक्सटेंशन के साथ समाप्त होने वाली हर एक फ़ाइल को हटाने का आदेश मिलता है।"}},
{type:"mcq",diff:"easy",en:{q:"Conversely to the asterisk, which specific wildcard character strictly represents exactly one single unknown alphanumeric character in command-line parsing?",opts:["*","@","?","!"],ans:2,exp:"The question mark (?) wildcard is highly restrictive. The shell mathematically interprets it as a placeholder for exactly one single character. For instance, executing a search for 'file?.doc' will successfully match 'file1.doc' and 'fileA.doc', but it will completely ignore a file named 'file12.doc'."},hi:{q:"तारांकन (*) के विपरीत, कौन सा विशिष्ट वाइल्डकार्ड वर्ण कमांड-लाइन पार्सिंग में ठीक एक एकल अज्ञात अल्फ़ान्यूमेरिक वर्ण (character) का प्रतिनिधित्व करता है?",opts:["*","@","?","!"],ans:2,exp:"प्रश्न चिह्न (?) वाइल्डकार्ड अत्यधिक प्रतिबंधात्मक है। शेल गणितीय रूप से इसे ठीक एक वर्ण के लिए प्लेसहोल्डर के रूप में व्याख्या करता है। उदाहरण के लिए, 'file?.doc' की खोज 'file1.doc' और 'fileA.doc' से सफलतापूर्वक मेल खाएगी, लेकिन यह 'file12.doc' को पूरी तरह से अनदेखा कर देगी।"}},
{type:"tf",diff:"easy",en:{q:"In the DOS environment, command execution is strictly case-sensitive, meaning typing 'dir' and 'DIR' will yield different mathematical results.",opts:["True","False"],ans:1,exp:"This is definitively False. MS-DOS and the Windows Command Prompt (cmd.exe) are architecturally case-insensitive. The command interpreter mathematically treats uppercase and lowercase characters identically, meaning executing 'DiR', 'dir', or 'dIr' will all flawlessly trigger the exact same directory listing operation."},hi:{q:"DOS वातावरण में, कमांड निष्पादन कड़ाई से केस-सेंसिटिव है, जिसका अर्थ है कि 'dir' और 'DIR' टाइप करने से अलग-अलग परिणाम मिलेंगे।",opts:["सही","गलत"],ans:1,exp:"यह निश्चित रूप से गलत है। MS-DOS और Windows कमांड प्रॉम्प्ट (cmd.exe) वास्तुशिल्प रूप से केस-इंसेंसिटिव हैं। कमांड इंटरप्रेटर अपरकेस और लोअरकेस वर्णों को समान रूप से मानता है, जिसका अर्थ है 'DiR', 'dir', या 'dIr' निष्पादित करने से समान परिणाम मिलेगा।"}},
{type:"tf",diff:"easy",en:{q:"Linux is mathematically engineered as a multi-user and multi-tasking operating system, allowing several people to execute distinct commands simultaneously.",opts:["True","False"],ans:0,exp:"This is True. Linux inherited its core architectural philosophy from Unix. It is mathematically designed from the kernel up to safely manage complex preemptive multitasking and strictly isolate independent user sessions, allowing hundreds of distinct users to SSH into a server and execute different scripts simultaneously without crashing the system."},hi:{q:"लिनक्स को गणितीय रूप से एक मल्टी-यूज़र और मल्टी-टास्किंग ऑपरेटिंग सिस्टम के रूप में इंजीनियर किया गया है, जो कई लोगों को एक साथ अलग-अलग कमांड निष्पादित करने की अनुमति देता है।",opts:["सही","गलत"],ans:0,exp:"यह सही है। लिनक्स ने यूनिक्स से अपना मुख्य वास्तुशिल्प दर्शन विरासत में प्राप्त किया। यह कर्नेल से लेकर प्रीमेप्टिव मल्टीटास्किंग को सुरक्षित रूप से प्रबंधित करने और स्वतंत्र उपयोगकर्ता सत्रों को सख्ती से अलग करने के लिए डिज़ाइन किया गया है, जिससे कई उपयोगकर्ता एक साथ सर्वर में लॉग इन कर सकते हैं।"}},

{type:"mcq",diff:"medium",en:{q:"In DOS, commands are structurally categorized into 'Internal' and 'External'. Which of the following is explicitly an External DOS command that requires a separate executable file?",opts:["DIR","COPY","FORMAT","CLS"],ans:2,exp:"Internal commands (like DIR, COPY, CLS) are mathematically embedded directly inside the 'COMMAND.COM' shell memory. External commands, however, are larger, more complex utilities that reside as standalone executable files on the hard disk (e.g., FORMAT.COM or XCOPY.EXE). The OS must physically locate and load them from disk into RAM to execute them."},hi:{q:"DOS में, कमांड को संरचनात्मक रूप से 'आंतरिक' (Internal) और 'बाहरी' (External) में वर्गीकृत किया गया है। निम्नलिखित में से कौन स्पष्ट रूप से एक बाहरी DOS कमांड है जिसके लिए एक अलग निष्पादन योग्य (executable) फ़ाइल की आवश्यकता होती है?",opts:["DIR","COPY","FORMAT (प्रारूप)","CLS"],ans:2,exp:"आंतरिक कमांड (जैसे DIR, COPY) सीधे 'COMMAND.COM' शेल मेमोरी के अंदर एम्बेडेड होते हैं। बाहरी कमांड स्टैंडअलोन निष्पादन योग्य फ़ाइलों (जैसे, FORMAT.COM) के रूप में हार्ड डिस्क पर रहते हैं। OS को उन्हें निष्पादित करने के लिए भौतिक रूप से खोजना और डिस्क से RAM में लोड करना होता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which highly specific DOS command is utilized to mathematically inspect a hard disk for logical file system errors and map physically bad sectors?",opts:["DISKSCAN","CHKDSK","FDISK","DEFRAG"],ans:1,exp:"The 'CHKDSK' (Check Disk) command is a powerful external diagnostic utility. It parses the file allocation table (FAT/NTFS) looking for cross-linked files, lost clusters, and mathematically verifies the integrity of the directory structure. Using parameters like '/f' allows it to aggressively fix logical errors it encounters."},hi:{q:"तार्किक फ़ाइल सिस्टम त्रुटियों के लिए हार्ड डिस्क का गणितीय रूप से निरीक्षण करने और भौतिक रूप से खराब क्षेत्रों (bad sectors) को मैप करने के लिए किस अत्यधिक विशिष्ट DOS कमांड का उपयोग किया जाता है?",opts:["DISKSCAN","CHKDSK","FDISK","DEFRAG"],ans:1,exp:"'CHKDSK' (चेक डिस्क) कमांड एक शक्तिशाली बाहरी डायग्नोस्टिक उपयोगिता है। यह क्रॉस-लिंक्ड फ़ाइलों, खोए हुए क्लस्टरों की तलाश में फ़ाइल आवंटन तालिका (FAT/NTFS) को पार्स करता है। '/f' जैसे मापदंडों का उपयोग करने से यह तार्किक त्रुटियों को आक्रामक रूप से ठीक कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"While the basic COPY command handles single files, what advanced DOS external command mathematically excels at copying entire massive directory trees, including nested empty subdirectories?",opts:["TREE","XCOPY","ROBOCOPY","CLONEDIR"],ans:1,exp:"'XCOPY' (Extended Copy) is a robust external DOS command mathematically superior to standard COPY. It processes file replication in memory blocks rather than file-by-file, making it faster. By appending specific switches like '/S' and '/E', it recursively replicates deeply nested directory structures, even mathematically including empty folders."},hi:{q:"जबकि मूल COPY कमांड एकल फ़ाइलों को संभालता है, कौन सा उन्नत DOS बाहरी कमांड गणितीय रूप से संपूर्ण निर्देशिका ट्री (directory trees) की प्रतिलिपि बनाने में उत्कृष्ट है, जिसमें नेस्टेड खाली उप-निर्देशिकाएं भी शामिल हैं?",opts:["TREE","XCOPY","ROBOCOPY","CLONEDIR"],ans:1,exp:"'XCOPY' (Extended Copy) एक मजबूत बाहरी DOS कमांड है जो मानक COPY से बेहतर है। यह फ़ाइल-दर-फ़ाइल के बजाय मेमोरी ब्लॉक में फ़ाइल प्रतिकृति को संसाधित करता है, जिससे यह तेज़ हो जाता है। '/S' और '/E' जैसे स्विच का उपयोग करके, यह नेस्टेड निर्देशिका संरचनाओं की प्रतिलिपि बनाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which DOS command is mathematically required to alter the hidden, read-only, archive, or system metadata properties of a file?",opts:["PROMPT","REN","ATTRIB","CHMOD"],ans:2,exp:"The 'ATTRIB' command is an external DOS utility specifically engineered to modify a file's mathematical attributes. By applying mathematical operators like '+' (to set) or '-' (to clear) alongside attribute flags (R for Read-only, H for Hidden, S for System), administrators can securely hide critical core OS files from casual viewing or accidental deletion."},hi:{q:"किसी फ़ाइल के छिपे हुए (hidden), रीड-ओनली, संग्रह (archive), या सिस्टम मेटाडेटा गुणों को बदलने के लिए गणितीय रूप से कौन सा DOS कमांड आवश्यक है?",opts:["PROMPT","REN","ATTRIB","CHMOD"],ans:2,exp:"'ATTRIB' कमांड एक बाहरी DOS उपयोगिता है जिसे विशेष रूप से फ़ाइल के गणितीय गुणों को संशोधित करने के लिए बनाया गया है। '+' या '-' के साथ विशेषता झंडे (R रीड-ओनली के लिए, H हिडन के लिए) लागू करके, प्रशासक महत्वपूर्ण कोर ओएस फ़ाइलों को सुरक्षित रूप से छिपा सकते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"If a directory contains thousands of files, executing a plain 'DIR' command causes the text to scroll uncontrollably. Which specific switch mathematically forces DIR to pause execution after displaying each single screen of output?",opts:["DIR /W","DIR /P","DIR /S","DIR /A"],ans:1,exp:"Appending the '/P' (Page) switch alters the mathematical execution of the DIR command. It buffers the standard output. Once the console screen physically fills with text lines, the process strictly halts, displaying a prompt like 'Press any key to continue...'. This gives the human user mathematically sufficient time to read the data before rendering the next page."},hi:{q:"यदि किसी निर्देशिका में हजारों फ़ाइलें हैं, तो 'DIR' कमांड निष्पादित करने से टेक्स्ट अनियंत्रित रूप से स्क्रॉल होता है। कौन सा विशिष्ट स्विच गणितीय रूप से DIR को आउटपुट के प्रत्येक स्क्रीन को प्रदर्शित करने के बाद निष्पादन को रोकने (pause) के लिए बाध्य करता है?",opts:["DIR /W","DIR /P","DIR /S","DIR /A"],ans:1,exp:"'/P' (पेज) स्विच को जोड़ने से DIR कमांड का गणितीय निष्पादन बदल जाता है। यह मानक आउटपुट को बफर करता है। एक बार कंसोल स्क्रीन भौतिक रूप से टेक्स्ट लाइनों से भर जाने के बाद, प्रक्रिया रुक जाती है, जिससे उपयोगकर्ता को डेटा पढ़ने के लिए पर्याप्त समय मिल जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which internal DOS command provides administrators the capability to dynamically alter the text string displayed mathematically to the left of the blinking cursor (e.g., changing 'C:\\>' to 'Ready>')?",opts:["ECHO","PATH","PROMPT","SET"],ans:2,exp:"The 'PROMPT' command alters the mathematical appearance of the command-line prompt. Using special meta-characters (like $P for the current path, and $G for the greater-than sign >), an administrator can extensively customize the visual interface, or completely replace the path with a static text string like 'Enter Command:'."},hi:{q:"कौन सा आंतरिक DOS कमांड प्रशासकों को चमकते हुए कर्सर के बाईं ओर गणितीय रूप से प्रदर्शित टेक्स्ट स्ट्रिंग को गतिशील रूप से बदलने की क्षमता प्रदान करता है (उदा. 'C:\\>' को 'Ready>' में बदलना)?",opts:["ECHO","PATH","PROMPT","SET"],ans:2,exp:"'PROMPT' कमांड कमांड-लाइन प्रॉम्प्ट के गणितीय स्वरूप को बदल देता है। विशेष मेटा-वर्णों का उपयोग करके, एक प्रशासक दृश्य इंटरफ़ेस को बड़े पैमाने पर अनुकूलित कर सकता है, या 'C:\\>' को अपनी पसंद के टेक्स्ट स्ट्रिंग के साथ बदल सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which external DOS utility generates an advanced graphical hierarchy representing the mathematical structure of all directories and subdirectories on a specific drive?",opts:["GRAPH","TREE","MAP","DIR /STRUCTURE"],ans:1,exp:"The 'TREE' command is a powerful visual utility. When executed, it recursively parses the Master File Table and prints a mathematically formatted, pseudo-graphical tree diagram using ASCII characters. This visually maps out the entire nested directory hierarchy, making complex nested folder structures instantly comprehensible to the human eye."},hi:{q:"कौन सी बाहरी DOS उपयोगिता एक उन्नत ग्राफिकल पदानुक्रम उत्पन्न करती है जो एक विशिष्ट ड्राइव पर सभी निर्देशिकाओं और उप-निर्देशिकाओं की गणितीय संरचना का प्रतिनिधित्व करती है?",opts:["GRAPH","TREE","MAP","DIR /STRUCTURE"],ans:1,exp:"'TREE' कमांड एक शक्तिशाली दृश्य उपयोगिता है। निष्पादित होने पर, यह ASCII वर्णों का उपयोग करके गणितीय रूप से स्वरूपित, छद्म-ग्राफिकल ट्री आरेख प्रिंट करता है। यह संपूर्ण नेस्टेड निर्देशिका पदानुक्रम को दृष्टिगत रूप से मैप करता है, जिससे जटिल फ़ोल्डर संरचनाएं तुरंत समझ में आ जाती हैं।"}},
{type:"mcq",diff:"medium",en:{q:"In a strictly formatted Linux environment, which fundamental typographical character represents the absolute root directory of the entire monolithic file system?",opts:["\\ (Backslash)","C:","/ (Forward Slash)","~ (Tilde)"],ans:2,exp:"Linux completely abandons the concept of 'Drive Letters' (like C: or D:) used by DOS. Instead, it utilizes a monolithic, unified mathematical tree structure. The absolute topmost foundational point of this entire file system hierarchy is mathematically represented exclusively by a single forward slash ('/'). Every other directory, drive, or mounted USB branches off downwards from this root."},hi:{q:"कड़ाई से स्वरूपित लिनक्स वातावरण में, कौन सा मौलिक टाइपोग्राफ़िकल वर्ण (character) संपूर्ण फ़ाइल सिस्टम की पूर्ण रूट निर्देशिका (root directory) का प्रतिनिधित्व करता है?",opts:["\\ (Backslash)","C:","/ (Forward Slash)","~ (Tilde)"],ans:2,exp:"लिनक्स DOS द्वारा उपयोग किए जाने वाले 'ड्राइव लेटर्स' की अवधारणा को पूरी तरह से छोड़ देता है। इसके बजाय, यह एक एकीकृत गणितीय ट्री संरचना का उपयोग करता है। इस पूरे फ़ाइल सिस्टम पदानुक्रम का सबसे ऊपरी बिंदु विशेष रूप से एक सिंगल फॉरवर्ड स्लैश ('/') द्वारा दर्शाया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Within a user's Linux home directory, which specific mathematical prefix dictates that a file or configuration folder should remain strictly hidden from standard 'ls' directory listings?",opts:["A tilde (~) prefix","An underscore (_) prefix","A period (.) prefix","A hash (#) prefix"],ans:2,exp:"In Unix and Linux file systems, secrecy is mathematically dictated by the filename itself. Any file or directory whose name explicitly begins with a simple period (e.g., '.bashrc' or '.config') is treated as a hidden system object. It will not render in the standard output of 'ls' unless the user mathematically forces the display by appending the '-a' (all) flag."},hi:{q:"उपयोगकर्ता की लिनक्स होम निर्देशिका के भीतर, कौन सा विशिष्ट गणितीय उपसर्ग यह निर्धारित करता है कि एक फ़ाइल या कॉन्फ़िगरेशन फ़ोल्डर मानक 'ls' निर्देशिका लिस्टिंग से सख्ती से छिपा रहना चाहिए?",opts:["एक टिल्ड (~) उपसर्ग","एक अंडरस्कोर (_) उपसर्ग","एक अवधि (.) उपसर्ग (Period prefix)","एक हैश (#) उपसर्ग"],ans:2,exp:"यूनिक्स और लिनक्स फ़ाइल सिस्टम में, गोपनीयता गणितीय रूप से फ़ाइल नाम द्वारा निर्धारित की जाती है। कोई भी फ़ाइल या निर्देशिका जिसका नाम स्पष्ट रूप से एक साधारण अवधि (.) से शुरू होता है, उसे एक छिपी हुई प्रणाली वस्तु के रूप में माना जाता है। इसे देखने के लिए 'ls -a' का उपयोग करना पड़ता है।"}},
{type:"mcq",diff:"medium",en:{q:"If a Linux system administrator needs to rapidly search deep within the text contents of thousands of log files for a specific error string, which highly robust command is utilized?",opts:["search","find","grep","locate"],ans:2,exp:"The 'grep' (Global Regular Expression Print) command is arguably the most powerful text-processing tool in Linux. It reads streams of data or massive log files and mathematically filters the lines against highly complex 'regular expression' patterns. It outputs strictly the specific mathematical lines of text that successfully match the search criteria, ignoring the rest."},hi:{q:"यदि किसी लिनक्स सिस्टम प्रशासक को किसी विशिष्ट त्रुटि स्ट्रिंग के लिए हजारों लॉग फ़ाइलों की टेक्स्ट सामग्री के भीतर गहराई से खोजने की आवश्यकता है, तो किस अत्यधिक मजबूत कमांड का उपयोग किया जाता है?",opts:["search","find","grep","locate"],ans:2,exp:"'grep' (Global Regular Expression Print) कमांड लिनक्स में सबसे शक्तिशाली टेक्स्ट-प्रोसेसिंग टूल है। यह डेटा स्ट्रीम या विशाल लॉग फ़ाइलों को पढ़ता है और जटिल 'नियमित अभिव्यक्ति' (regular expression) पैटर्न के विरुद्ध लाइनों को गणितीय रूप से फ़िल्टर करता है। यह केवल उन पंक्तियों को आउटपुट करता है जो खोज मानदंडों से मेल खाती हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which fundamental Linux command enables an administrator to mathematically alter the strict Read, Write, and Execute access permissions of a file?",opts:["chown","attrib","chmod","perms"],ans:2,exp:"The 'chmod' (Change Mode) command is deeply integrated into Linux security. It alters the mathematical permission matrix (rwx) assigned to the Owner, the Group, and Others. Administrators execute it utilizing either symbolic syntax (e.g., 'chmod u+x file') to add execute rights for the user, or absolute octal numbers (e.g., 'chmod 755 file')."},hi:{q:"कौन सा मौलिक लिनक्स कमांड एक प्रशासक को फ़ाइल के सख्त रीड, राइट और एक्सीक्यूट (Execute) एक्सेस अनुमतियों को गणितीय रूप से बदलने में सक्षम बनाता है?",opts:["chown","attrib","chmod","perms"],ans:2,exp:"'chmod' (Change Mode) कमांड लिनक्स सुरक्षा में गहराई से एकीकृत है। यह स्वामी, समूह और अन्य को सौंपे गए गणितीय अनुमति मैट्रिक्स (rwx) को बदल देता है। प्रशासक उपयोगकर्ता के लिए अधिकारों को जोड़ने के लिए प्रतीकात्मक सिंटैक्स (जैसे, 'chmod u+x file') या ऑक्टल नंबर (जैसे, 'chmod 755 file') का उपयोग करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"In advanced Linux command-line architecture, what does the 'Pipe' operator (|) mathematically achieve when placed exactly between two distinct commands?",opts:["It executes both commands entirely simultaneously in background parallel threads","It mathematically captures the standard text output (stdout) of the first left-side command and injects it forcefully as the standard text input (stdin) for the second right-side command","It combines the syntax of both commands into an alias","It mathematically prevents the second command from executing if the first command fails"],ans:1,exp:"Piping is a foundational Unix philosophy concept. The pipe character '|' mathematically acts as a temporary data conduit. If a user types 'ls -la | less', the operating system captures the massive text output generated by the 'ls' command, prevents it from spilling onto the monitor, and instead channels it directly into the 'less' command for structured, paginated reading."},hi:{q:"उन्नत लिनक्स कमांड-लाइन वास्तुकला में, जब 'पाइप' ऑपरेटर (|) को ठीक दो अलग-अलग कमांड के बीच रखा जाता है तो यह गणितीय रूप से क्या प्राप्त करता है?",opts:["यह पृष्ठभूमि समानांतर थ्रेड्स में दोनों कमांड को पूरी तरह से एक साथ निष्पादित करता है","यह पहले बाएँ-पक्ष के कमांड के मानक टेक्स्ट आउटपुट (stdout) को कैप्चर करता है और इसे दूसरे दाएँ-पक्ष के कमांड के मानक टेक्स्ट इनपुट (stdin) के रूप में बलपूर्वक इंजेक्ट करता है","यह दोनों कमांड के सिंटैक्स को एक उपनाम (alias) में जोड़ता है","यह गणितीय रूप से दूसरे कमांड को निष्पादित होने से रोकता है यदि पहला कमांड विफल हो जाता है"],ans:1,exp:"पाइपिंग एक आधारभूत यूनिक्स दर्शन अवधारणा है। पाइप वर्ण '|' गणितीय रूप से एक अस्थायी डेटा नाली के रूप में कार्य करता है। यह पहले कमांड के आउटपुट को कैप्चर करता है और इसे संरचित पढ़ने के लिए सीधे दूसरे कमांड (जैसे less) में चैनल करता है।"}},
{type:"mcq",diff:"medium",en:{q:"When manipulating standard streams in the Linux shell, what does the double greater-than operator (>>) mathematically execute?",opts:["It brutally overwrites the target file, destroying all previous mathematical data within it","It gracefully captures standard output and appends the new text mathematically to the absolute bottom of the target file without destroying the existing contents","It redirects input from a file into a running command","It shifts the active process into a dormant background state"],ans:1,exp:"Output redirection is heavily utilized in scripting. The single '>' operator is highly destructive; it mathematically creates a new file or completely wipes an existing one before writing data. Conversely, the double '>>' operator is safe; it opens the existing file, seeks the absolute mathematical end of the current data block, and safely appends the new text lines beneath it."},hi:{q:"लिनक्स शेल में मानक स्ट्रीम में हेरफेर करते समय, डबल ग्रेटर-दैन ऑपरेटर (>>) गणितीय रूप से क्या निष्पादित करता है?",opts:["यह लक्षित फ़ाइल को बुरी तरह से अधिलेखित कर देता है, जिससे उसके भीतर का सभी पिछला डेटा नष्ट हो जाता है","यह मानक आउटपुट को कैप्चर करता है और मौजूदा सामग्री को नष्ट किए बिना लक्षित फ़ाइल के पूर्ण निचले भाग में नया टेक्स्ट जोड़ता (append) है","यह किसी फ़ाइल से इनपुट को चल रहे कमांड में पुनर्निर्देशित करता है","यह सक्रिय प्रक्रिया को एक निष्क्रिय पृष्ठभूमि स्थिति में बदल देता है"],ans:1,exp:"आउटपुट रीडायरेक्शन का बड़े पैमाने पर उपयोग किया जाता है। सिंगल '>' ऑपरेटर अत्यधिक विनाशकारी है; यह फ़ाइल को पूरी तरह से मिटा देता है। इसके विपरीत, डबल '>>' ऑपरेटर सुरक्षित है; यह मौजूदा फ़ाइल को खोलता है और सुरक्षित रूप से इसके नीचे नई टेक्स्ट लाइनें जोड़ता है (append करता है)।"}},
{type:"mcq",diff:"medium",en:{q:"Which core Linux administrative command provides a highly detailed, dynamically updating graphical snapshot of active background processes, PID numbers, and real-time CPU/RAM utilization?",opts:["ps","top","kill","grep"],ans:1,exp:"While 'ps' prints a static, one-time list of current processes, the 'top' command provides a robust, continuous, real-time interface. It mathematically sorts all running system processes based on their live CPU or memory consumption, refreshing every few seconds. It acts essentially as the CLI equivalent of the graphical Windows Task Manager."},hi:{q:"कौन सा कोर लिनक्स प्रशासनिक कमांड सक्रिय पृष्ठभूमि प्रक्रियाओं, PID नंबरों और वास्तविक समय CPU/RAM उपयोग का एक अत्यधिक विस्तृत, गतिशील रूप से अद्यतन ग्राफिकल स्नैपशॉट प्रदान करता है?",opts:["ps","top","kill","grep"],ans:1,exp:"जबकि 'ps' वर्तमान प्रक्रियाओं की एक स्थिर सूची प्रिंट करता है, 'top' कमांड एक मजबूत, निरंतर, वास्तविक समय इंटरफ़ेस प्रदान करता है। यह अपने लाइव CPU या मेमोरी खपत के आधार पर सभी चल रही सिस्टम प्रक्रियाओं को गणितीय रूप से सॉर्ट करता है, जो हर कुछ सेकंड में ताज़ा होता है।"}},
{type:"mcq",diff:"medium",en:{q:"If a runaway graphical application mathematically locks up a Linux desktop, which concise command is utilized from the terminal to aggressively terminate the rogue process using its specific PID?",opts:["stop","halt","kill","terminate"],ans:2,exp:"The 'kill' command is the architectural mechanism used to mathematically send strict termination signals to active background processes. By identifying the malfunctioning process's Process ID (PID) via 'top' or 'ps', an administrator can issue a command like 'kill 1234'. If the process refuses to gracefully exit, the administrator escalates to 'kill -9 1234' to force immediate termination at the kernel level."},hi:{q:"यदि एक ग्राफिकल एप्लिकेशन गणितीय रूप से लिनक्स डेस्कटॉप को लॉक कर देता है, तो इसके विशिष्ट PID का उपयोग करके दुष्ट प्रक्रिया को आक्रामक रूप से समाप्त करने के लिए टर्मिनल से किस संक्षिप्त कमांड का उपयोग किया जाता है?",opts:["stop","halt","kill","terminate"],ans:2,exp:"'kill' कमांड वह तंत्र है जिसका उपयोग सक्रिय पृष्ठभूमि प्रक्रियाओं को समाप्ति संकेत भेजने के लिए किया जाता है। 'top' या 'ps' के माध्यम से प्रक्रिया की PID की पहचान करके, एक प्रशासक 'kill 1234' जैसे कमांड जारी कर सकता है। कर्नेल स्तर पर तत्काल समाप्ति को बाध्य करने के लिए 'kill -9' का उपयोग किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"In the strict, monolithic Linux File System Hierarchy Standard (FHS), which specific absolute directory exclusively houses system-wide mathematical configuration text files?",opts:["/bin","/usr","/home","/etc"],ans:3,exp:"The '/etc' (Etcetera) directory is fundamentally the central nervous system of Linux configuration. It contains absolutely zero executable binaries. Instead, it strictly houses massive arrays of static, human-readable text configuration files that mathematically dictate how the network, bootloader, installed services (like Apache or SSH), and system hardware behave during operation."},hi:{q:"कठोर लिनक्स फ़ाइल सिस्टम पदानुक्रम मानक (FHS) में, कौन सी विशिष्ट पूर्ण निर्देशिका (directory) विशेष रूप से सिस्टम-व्यापी गणितीय कॉन्फ़िगरेशन टेक्स्ट फ़ाइलों को रखती है?",opts:["/bin","/usr","/home","/etc"],ans:3,exp:"'/etc' निर्देशिका मौलिक रूप से लिनक्स कॉन्फ़िगरेशन का केंद्रीय तंत्रिका तंत्र है। इसमें बिल्कुल शून्य निष्पादन योग्य (executables) होते हैं। इसके बजाय, यह कॉन्फ़िगरेशन फ़ाइलों को रखता है जो गणितीय रूप से निर्देशित करते हैं कि नेटवर्क, बूटलोडर, स्थापित सेवाएं और सिस्टम हार्डवेयर कैसे व्यवहार करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Under the Linux FHS, the '/bin' directory strictly functions as the repository for what specific type of system data?",opts:["Graphical user wallpapers","Log files generated by the kernel","Essential, compiled command-line executable programs heavily required by all users (like ls, cp, bash)","Temporary mathematical swap files"],ans:2,exp:"The '/bin' (Binary) directory mathematically holds the most fundamental, stripped-down executable programs essential for the operating system to function at a basic level. Core shell utilities heavily relied upon by standard users and the root administrator alike—such as 'ls', 'cp', 'mkdir', and the 'bash' shell itself—are physically compiled and stored precisely in this directory."},hi:{q:"लिनक्स FHS के तहत, '/bin' निर्देशिका विशेष रूप से किस प्रकार के सिस्टम डेटा के भंडार के रूप में कार्य करती है?",opts:["ग्राफिकल यूजर वॉलपेपर","कर्नेल द्वारा उत्पन्न लॉग फ़ाइलें","सभी उपयोगकर्ताओं द्वारा अत्यधिक आवश्यक आवश्यक, संकलित कमांड-लाइन निष्पादन योग्य प्रोग्राम (जैसे ls, cp, bash)","अस्थायी गणितीय स्वैप फ़ाइलें"],ans:2,exp:"'/bin' (बाइनरी) निर्देशिका गणितीय रूप से ऑपरेटिंग सिस्टम के मूल स्तर पर कार्य करने के लिए आवश्यक सबसे मौलिक, निष्पादन योग्य कार्यक्रमों को रखती है। कोर शेल उपयोगिताओं (जैसे 'ls', 'cp', 'mkdir', और स्वयं 'bash' शेल) भौतिक रूप से संकलित होती हैं और इस निर्देशिका में संग्रहीत होती हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which robust Linux administrative command is utilized specifically to mathematically transfer the absolute physical ownership of a file or directory from one user account to another?",opts:["chmod","chgrp","chown","useradd"],ans:2,exp:"The 'chown' (Change Owner) command is a critical security utility. While 'chmod' alters what a user can physically do with a file, 'chown' mathematically reassigns the absolute ownership hierarchy. Only the all-powerful 'root' user possesses the architectural authority to forcefully strip ownership from one user and reassign it to a completely different user ID."},hi:{q:"एक उपयोगकर्ता खाते से दूसरे उपयोगकर्ता खाते में किसी फ़ाइल या निर्देशिका के पूर्ण भौतिक स्वामित्व (ownership) को गणितीय रूप से स्थानांतरित करने के लिए विशेष रूप से किस मजबूत लिनक्स प्रशासनिक कमांड का उपयोग किया जाता है?",opts:["chmod","chgrp","chown","useradd"],ans:2,exp:"'chown' (Change Owner) कमांड एक महत्वपूर्ण सुरक्षा उपयोगिता है। जबकि 'chmod' यह बदलता है कि कोई उपयोगकर्ता किसी फ़ाइल के साथ क्या कर सकता है, 'chown' गणितीय रूप से पूर्ण स्वामित्व पदानुक्रम को पुन: असाइन करता है। केवल शक्तिशाली 'रूट' (root) उपयोगकर्ता के पास यह अधिकार होता है।"}},
{type:"mcq",diff:"medium",en:{q:"In DOS and Windows command-line environments, saving a raw text file containing a structured sequence of commands with the specific '.bat' extension creates what architectural asset?",opts:["A compressed zip archive","A compiled executable binary program","A mathematical Batch Script file executed linearly by the command interpreter","A hidden system registry file"],ans:2,exp:"A file carrying the '.bat' extension is structurally identified by the OS as a Batch Script. It is simply an uncompiled, raw ASCII text file containing lines of specific DOS commands. When mathematically executed by the user, the 'COMMAND.COM' or 'cmd.exe' interpreter reads the file and brutally executes every single command sequentially, fully automating highly repetitive administrative tasks."},hi:{q:"DOS और Windows कमांड-लाइन वातावरण में, विशिष्ट '.bat' एक्सटेंशन के साथ कमांड के संरचित अनुक्रम वाले कच्चे टेक्स्ट फ़ाइल को सहेजने से क्या वास्तुशिल्प संपत्ति (asset) बनती है?",opts:["एक संपीड़ित ज़िप संग्रह","एक संकलित निष्पादन योग्य बाइनरी प्रोग्राम","कमांड इंटरप्रेटर द्वारा रैखिक रूप से निष्पादित एक गणितीय बैच स्क्रिप्ट फ़ाइल (Batch Script file)","एक छिपी हुई सिस्टम रजिस्ट्री फ़ाइल"],ans:2,exp:"'.bat' एक्सटेंशन वाली फ़ाइल को OS द्वारा बैच स्क्रिप्ट (Batch Script) के रूप में संरचनात्मक रूप से पहचाना जाता है। यह एक कच्ची ASCII टेक्स्ट फ़ाइल है जिसमें विशिष्ट DOS कमांड की पंक्तियाँ होती हैं। निष्पादित होने पर, इंटरप्रेटर फ़ाइल को पढ़ता है और प्रशासनिक कार्यों को स्वचालित करते हुए हर कमांड को क्रमिक रूप से निष्पादित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which widely used, natively pre-installed Linux terminal text editor allows system administrators to mathematically alter complex configuration files without relying on a graphical user interface?",opts:["MS Word","vi (or nano)","Notepad++","GIMP"],ans:1,exp:"The 'vi' (Visual) editor, or its modernized cousin 'vim', along with the simpler 'nano' editor, are terminal-based text editors deeply hardcoded into almost all Linux distributions. Because enterprise servers strictly operate completely without a GUI to conserve RAM, administrators mathematically rely on 'vi' to parse and edit crucial '/etc' configuration files using complex keyboard commands."},hi:{q:"व्यापक रूप से उपयोग किया जाने वाला, मूल रूप से पहले से स्थापित लिनक्स टर्मिनल टेक्स्ट एडिटर कौन सा है जो सिस्टम प्रशासकों को ग्राफिकल यूजर इंटरफेस (GUI) पर निर्भर किए बिना जटिल कॉन्फ़िगरेशन फ़ाइलों को गणितीय रूप से बदलने की अनुमति देता है?",opts:["MS Word","vi (या nano)","Notepad++","GIMP"],ans:1,exp:"'vi' (विज़ुअल) एडिटर, या 'vim' और 'nano' एडिटर, टर्मिनल-आधारित टेक्स्ट एडिटर हैं जो लगभग सभी लिनक्स वितरणों में हार्डकोडेड हैं। चूँकि एंटरप्राइज़ सर्वर RAM के संरक्षण के लिए पूरी तरह से GUI के बिना काम करते हैं, इसलिए प्रशासक कॉन्फ़िगरेशन फ़ाइलों को संपादित करने के लिए 'vi' पर निर्भर करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"If a Linux user encounters an entirely unfamiliar command-line utility, which specific command mathematically prints the extensive, official, built-in documentation manual for that tool?",opts:["help","info","man","doc"],ans:2,exp:"The 'man' (Manual) command is the absolute standard for Linux documentation. By executing 'man ls' or 'man grep', the system opens a dedicated, paginated terminal pager containing the rigorous mathematical syntax, exhaustive flag parameters, detailed explanations, and usage examples explicitly written by the original software developers."},hi:{q:"यदि किसी लिनक्स उपयोगकर्ता को पूरी तरह से अपरिचित कमांड-लाइन उपयोगिता का सामना करना पड़ता है, तो कौन सा विशिष्ट कमांड गणितीय रूप से उस उपकरण के लिए व्यापक, आधिकारिक, अंतर्निहित प्रलेखन मैनुअल (documentation manual) प्रिंट करता है?",opts:["help","info","man","doc"],ans:2,exp:"'man' (Manual) कमांड लिनक्स प्रलेखन के लिए पूर्ण मानक है। 'man ls' या 'man grep' को निष्पादित करने से, सिस्टम एक समर्पित टर्मिनल पेजर खोलता है जिसमें मूल सॉफ्टवेयर डेवलपर्स द्वारा लिखे गए कठोर गणितीय सिंटैक्स, विस्तृत स्पष्टीकरण और उपयोग के उदाहरण होते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"When analyzing the highly structured output of the 'ls -l' command in Linux, what explicit permission is granted to a user if they mathematically possess the 'x' flag on a specific file?",opts:["The right to mathematically extract a compressed archive","The right to explicitly execute the file as a compiled program or script","The right to export the file over the network","The right to securely encrypt the file"],ans:1,exp:"In the rigid Linux permission matrix (rwx), 'r' designates Read capability, 'w' designates Write/modify capability, and 'x' explicitly grants Execute capability. If a bash script or compiled binary lacks the mathematical 'x' flag, the kernel will aggressively block the user from running the program, returning a strict 'Permission denied' error, even if the user owns the file."},hi:{q:"लिनक्स में 'ls -l' कमांड के अत्यधिक संरचित आउटपुट का विश्लेषण करते समय, किसी उपयोगकर्ता को कौन सी स्पष्ट अनुमति दी जाती है यदि वे गणितीय रूप से किसी विशिष्ट फ़ाइल पर 'x' ध्वज (flag) रखते हैं?",opts:["संपीड़ित संग्रह को गणितीय रूप से निकालने का अधिकार","संकलित प्रोग्राम या स्क्रिप्ट के रूप में फ़ाइल को स्पष्ट रूप से निष्पादित (execute) करने का अधिकार","नेटवर्क पर फ़ाइल निर्यात करने का अधिकार","फ़ाइल को सुरक्षित रूप से एन्क्रिप्ट करने का अधिकार"],ans:1,exp:"कठोर लिनक्स अनुमति मैट्रिक्स (rwx) में, 'r' पढ़ने की क्षमता, 'w' लिखने/संशोधित करने की क्षमता, और 'x' स्पष्ट रूप से निष्पादित (Execute) करने की क्षमता प्रदान करता है। यदि किसी स्क्रिप्ट या संकलित बाइनरी में 'x' ध्वज का अभाव है, तो कर्नेल उपयोगकर्ता को प्रोग्राम चलाने से रोक देगा।"}},
{type:"mcq",diff:"medium",en:{q:"What fundamental internal command is heavily utilized in DOS and Linux batch scripting to print explicit custom text strings and mathematical variables visibly onto the terminal screen?",opts:["PRINT","WRITE","ECHO","DISPLAY"],ans:2,exp:"The 'ECHO' command is ubiquitous across OS scripting languages. When a script executes 'echo Hello World', the string is mathematically captured and pushed directly to the standard output device (the screen). It is an indispensable architectural tool used to communicate script progress, print raw mathematical variable data, or pipe text directly into files (e.g., 'echo data > file.txt')."},hi:{q:"स्पष्ट कस्टम टेक्स्ट स्ट्रिंग और गणितीय चर को टर्मिनल स्क्रीन पर स्पष्ट रूप से प्रिंट करने के लिए DOS और Linux बैच स्क्रिप्टिंग में किस मौलिक आंतरिक कमांड का भारी उपयोग किया जाता है?",opts:["PRINT","WRITE","ECHO","DISPLAY"],ans:2,exp:"'ECHO' कमांड OS स्क्रिप्टिंग भाषाओं में सर्वव्यापी है। जब कोई स्क्रिप्ट 'echo Hello World' निष्पादित करती है, तो स्ट्रिंग को सीधे मानक आउटपुट डिवाइस (स्क्रीन) पर धकेल दिया जाता है। यह स्क्रिप्ट प्रगति को संप्रेषित करने, या फ़ाइलों में सीधे टेक्स्ट पाइप करने के लिए उपयोग किया जाने वाला एक अनिवार्य उपकरण है।"}},
{type:"mcq",diff:"medium",en:{q:"In DOS, what specific command line utility is explicitly mathematically designed to arrange lines of text from an input file into alphabetical or reverse-alphabetical order?",opts:["ORDER","ARRANGE","SORT","ORGANIZE"],ans:2,exp:"The 'SORT' command acts as an external text filter in DOS. It accepts raw text input (either from a designated file or mathematically piped from another command), reads it line by line, and algorithmically sorts the data either alphabetically (A-Z) or in reverse (Z-A) before pushing the rigorously organized output to the console or another file."},hi:{q:"DOS में, इनपुट फ़ाइल से टेक्स्ट की पंक्तियों को वर्णानुक्रम या रिवर्स-वर्णानुक्रम में व्यवस्थित करने के लिए स्पष्ट रूप से किस विशिष्ट कमांड लाइन उपयोगिता को गणितीय रूप से डिज़ाइन किया गया है?",opts:["ORDER","ARRANGE","SORT","ORGANIZE"],ans:2,exp:"'SORT' कमांड DOS में एक बाहरी टेक्स्ट फ़िल्टर के रूप में कार्य करता है। यह कच्चे टेक्स्ट इनपुट को स्वीकार करता है, इसे लाइन दर लाइन पढ़ता है, और संगठित आउटपुट को कंसोल या किसी अन्य फ़ाइल में धकेलने से पहले एल्गोरिथम रूप से वर्णानुक्रम (A-Z) या रिवर्स (Z-A) में डेटा को सॉर्ट करता है।"}},
{type:"tf",diff:"medium",en:{q:"In Linux architecture, the core foundational philosophy is that absolutely every single system component, including hardware devices, keyboards, and active memory processes, is mathematically represented as a 'File'.",opts:["True","False"],ans:0,exp:"This is profoundly True. The Unix/Linux philosophy explicitly dictates 'Everything is a file'. To the kernel, a text document, a directory, a physical hard drive mapped in '/dev', and even an active network socket are all mathematically treated utilizing identical file I/O operations (read, write, open, close), creating a brilliantly unified and elegant system architecture."},hi:{q:"लिनक्स वास्तुकला में, मुख्य आधारभूत दर्शन यह है कि हार्डवेयर उपकरणों, कीबोर्ड और सक्रिय मेमोरी प्रक्रियाओं सहित प्रत्येक सिस्टम घटक को गणितीय रूप से 'फ़ाइल' के रूप में दर्शाया जाता है।",opts:["सही","गलत"],ans:0,exp:"यह गहराई से सत्य है। यूनिक्स/लिनक्स दर्शन स्पष्ट रूप से निर्देशित करता है कि 'सब कुछ एक फ़ाइल है'। कर्नेल के लिए, एक टेक्स्ट दस्तावेज़, एक निर्देशिका, '/dev' में मैप की गई एक भौतिक हार्ड ड्राइव, और यहां तक ​​कि एक सक्रिय नेटवर्क सॉकेट सभी को गणितीय रूप से फ़ाइल संचालन (पढ़ने, लिखने) का उपयोग करके माना जाता है।"}},
{type:"tf",diff:"medium",en:{q:"In standard MS-DOS, the 'DEL' command is robust enough to mathematically delete entire directories along with all nested subdirectories and files in a single execution.",opts:["True","False"],ans:1,exp:"This is unequivocally False. The basic 'DEL' (Delete) command is mathematically restricted to removing only individual files. It completely lacks the algorithmic capability to delete directory structures. To physically remove entire directory trees, a user must meticulously empty them first and use 'RD', or utilize advanced external utilities like 'DELTREE' or 'RMDIR /S' in modern Windows command prompts."},hi:{q:"मानक MS-DOS में, 'DEL' कमांड एक ही निष्पादन में सभी नेस्टेड उप-निर्देशिकाओं और फ़ाइलों के साथ संपूर्ण निर्देशिकाओं को गणितीय रूप से हटाने के लिए पर्याप्त मजबूत है।",opts:["सही","गलत"],ans:1,exp:"यह स्पष्ट रूप से गलत है। मूल 'DEL' (डिलीट) कमांड गणितीय रूप से केवल व्यक्तिगत फ़ाइलों को हटाने तक सीमित है। इसमें निर्देशिका संरचनाओं (directories) को हटाने की क्षमता का पूरी तरह से अभाव है। संपूर्ण निर्देशिका ट्री को भौतिक रूप से हटाने के लिए, उपयोगकर्ता को पहले उन्हें खाली करना होगा और 'RD' का उपयोग करना होगा।"}},

{type:"mcq",diff:"hard",en:{q:"In the strict Linux permission architecture, what does the octal numeric command 'chmod 755' mathematically enforce upon a target file or script?",opts:["The Owner receives absolute read, write, and execute rights (7), while both the Group and Others are strictly limited to reading and executing (5), physically blocking them from modifying the file","It grants absolute root privileges to all users temporarily","It mathematically deletes the file completely after 755 seconds","It compresses the file aggressively to 755 bytes"],ans:0,exp:"Linux translates permissions using mathematically additive octal blocks: Read=4, Write=2, Execute=1. The first digit maps to the Owner, the second to the Group, and the third to Others. Therefore, an octal '7' is 4+2+1 (Read/Write/Execute). An octal '5' is 4+1 (Read/Execute). '755' is the ultimate standard for web directories and bash scripts, securing write access solely to the creator while allowing public execution."},hi:{q:"कठोर लिनक्स अनुमति वास्तुकला में, ऑक्टल संख्यात्मक कमांड 'chmod 755' एक लक्ष्य फ़ाइल या स्क्रिप्ट पर गणितीय रूप से क्या लागू करता है?",opts:["स्वामी को पूर्ण रूप से पढ़ने, लिखने और निष्पादित करने का अधिकार (7) मिलता है, जबकि समूह और अन्य दोनों कड़ाई से पढ़ने और निष्पादित करने (5) तक सीमित हैं, जो उन्हें फ़ाइल को संशोधित करने से रोकता है","यह अस्थायी रूप से सभी उपयोगकर्ताओं को पूर्ण रूट विशेषाधिकार प्रदान करता है","यह 755 सेकंड के बाद फ़ाइल को पूरी तरह से गणितीय रूप से हटा देता है","यह फ़ाइल को आक्रामक रूप से 755 बाइट्स तक संपीड़ित करता है"],ans:0,exp:"लिनक्स गणितीय रूप से योगात्मक ऑक्टल ब्लॉक का उपयोग करके अनुमतियों का अनुवाद करता है: Read=4, Write=2, Execute=1। पहला अंक स्वामी (Owner) के लिए है, दूसरा समूह (Group) के लिए है, और तीसरा अन्य (Others) के लिए है। '7' 4+2+1 (रीड/राइट/एक्जीक्यूट) है। '5' 4+1 (रीड/एक्जीक्यूट) है।"}},
{type:"mcq",diff:"hard",en:{q:"If a Linux system administrator executes 'chmod 644 config.txt', what is the exact mathematical resulting permission matrix generated for that configuration file?",opts:["rwxrwxrwx","rw-rw-rw-","r--r--r--","rw-r--r--"],ans:3,exp:"Using the octal bitmask (R=4, W=2, X=1): The Owner gets '6' (4+2 = Read and Write), represented as 'rw-'. The Group gets '4' (Read only), represented as 'r--'. Others get '4' (Read only), represented as 'r--'. Combining these strings geometrically yields 'rw-r--r--'. This is the mathematically optimal baseline security permission for standard non-executable configuration files, preventing unauthorized sabotage."},hi:{q:"यदि लिनक्स सिस्टम प्रशासक 'chmod 644 config.txt' निष्पादित करता है, तो उस कॉन्फ़िगरेशन फ़ाइल के लिए उत्पन्न सटीक गणितीय परिणामी अनुमति मैट्रिक्स क्या है?",opts:["rwxrwxrwx","rw-rw-rw-","r--r--r--","rw-r--r--"],ans:3,exp:"ऑक्टल बिटमास्क (R=4, W=2, X=1) का उपयोग करते हुए: स्वामी को '6' (4+2 = रीड एंड राइट) मिलता है, जिसे 'rw-' के रूप में दर्शाया जाता है। समूह को '4' (केवल रीड) मिलता है, जिसे 'r--' के रूप में दर्शाया जाता है। अन्य को '4' (केवल रीड) मिलता है। इन्हें जोड़ने पर 'rw-r--r--' प्राप्त होता है।"}},
{type:"mcq",diff:"hard",en:{q:"When executing the DOS command 'ATTRIB +h +r +s bootmgr', what explicit metadata states are being aggressively forced onto the target file?",opts:["The file is designated as a High-priority, Recursive, System executable","The file is mathematically configured to be Hidden from standard directory listings, locked as Read-only to prevent modification, and flagged as a critical System file to warn the OS against tampering","The file is Compressed, Relocated, and Shrunk","The file is Hard-linked, Renamed, and Shared"],ans:1,exp:"The 'ATTRIB' command manipulates file metadata mathematically. The '+' operator applies the flag. '+H' sets the Hidden attribute, physically removing it from standard 'DIR' output. '+R' enforces Read-only status, blocking write-access and accidental deletion. '+S' flags the file as an integral part of the Operating System. Combining these three structurally shields critical boot files from ignorant users."},hi:{q:"DOS कमांड 'ATTRIB +h +r +s bootmgr' को निष्पादित करते समय, लक्ष्य फ़ाइल पर आक्रामक रूप से किन स्पष्ट मेटाडेटा स्थितियों को बाध्य किया जा रहा है?",opts:["फ़ाइल को उच्च-प्राथमिकता, पुनरावर्ती (Recursive), सिस्टम निष्पादन योग्य के रूप में नामित किया गया है","फ़ाइल को गणितीय रूप से छिपी हुई (Hidden) होने के लिए कॉन्फ़िगर किया गया है, संशोधन को रोकने के लिए रीड-ओनली के रूप में लॉक किया गया है, और एक महत्वपूर्ण सिस्टम फ़ाइल के रूप में ध्वजांकित किया गया है","फ़ाइल संकुचित (Compressed), स्थानांतरित और सिकुड़ी हुई है","फ़ाइल हार्ड-लिंक्ड, रिनेम और शेयर्ड है"],ans:1,exp:"'ATTRIB' कमांड फ़ाइल मेटाडेटा में गणितीय रूप से हेरफेर करता है। '+' ऑपरेटर ध्वज लागू करता है। '+H' हिडन (Hidden) विशेषता सेट करता है। '+R' रीड-ओनली स्थिति लागू करता है, लेखन-पहुंच को अवरुद्ध करता है। '+S' फ़ाइल को ऑपरेटिंग सिस्टम के अभिन्न अंग के रूप में फ़्लैग करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In a catastrophic scenario, if a root administrator blindly executes 'rm -rf /' in a Linux shell, what is the absolute mathematical result?",opts:["The system aggressively reboots instantly","The command physically format the RAM","The shell utilizes the recursive (-r) and force (-f) flags starting explicitly at the root directory (/), systematically and irreversibly deleting absolutely every single file, configuration, and kernel module across the entire operating system, utterly destroying the machine","The system creates a backup of the root filesystem"],ans:2,exp:"This is the most famously destructive command in Linux. 'rm' is remove. The '-r' flag forces the mathematical algorithm to dig recursively into every nested subdirectory. The '-f' (force) flag aggressively suppresses all safety prompts. By targeting '/', the absolute root of the FHS tree, the command mathematically annihilates the entire operating system file by file until it crashes itself out of existence."},hi:{q:"एक विनाशकारी परिदृश्य में, यदि कोई रूट प्रशासक आँख बंद करके लिनक्स शेल में 'rm -rf /' निष्पादित करता है, तो इसका पूर्ण गणितीय परिणाम क्या है?",opts:["सिस्टम आक्रामक रूप से तुरंत रीबूट हो जाता है","कमांड भौतिक रूप से रैम (RAM) को फॉर्मेट करता है","शेल रूट डायरेक्टरी (/) से शुरू होकर पुनरावर्ती (-r) और बल (-f) झंडे का उपयोग करता है, जो पूरे ऑपरेटिंग सिस्टम में हर फ़ाइल और कर्नेल मॉड्यूल को व्यवस्थित और अपरिवर्तनीय रूप से हटा देता है, मशीन को पूरी तरह नष्ट कर देता है","सिस्टम रूट फ़ाइल सिस्टम का बैकअप बनाता है"],ans:2,exp:"यह लिनक्स में सबसे प्रसिद्ध विनाशकारी कमांड है। 'rm' रिमूव है। '-r' ध्वज गणितीय एल्गोरिथ्म को प्रत्येक उप-निर्देशिका में गहराई तक जाने के लिए बाध्य करता है। '-f' (बल) ध्वज सुरक्षा संकेतों को दबा देता है। '/' (रूट) को लक्षित करके, कमांड गणितीय रूप से पूरे ऑपरेटिंग सिस्टम को नष्ट कर देता है।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced Linux process management, if a zombie process utterly ignores standard termination requests, which absolute kill signal must the administrator inject to mathematically force the kernel to abruptly sever the process from RAM?",opts:["SIGTERM (15)","SIGHUP (1)","SIGINT (2)","SIGKILL (9)"],ans:3,exp:"When an administrator types 'kill PID', the default signal sent is SIGTERM (15), politely requesting the process to mathematically shut down its own operations. If the process is deadlocked, it ignores this. The administrator escalates to 'kill -9 PID'. The '9' represents SIGKILL. This signal mathematically bypasses the application entirely; the kernel intercepts it and brutally, instantly purges the application's allocated memory blocks without cleanup."},hi:{q:"उन्नत लिनक्स प्रक्रिया प्रबंधन में, यदि कोई ज़ोंबी प्रक्रिया मानक समाप्ति अनुरोधों को पूरी तरह से अनदेखा करती है, तो प्रशासक को कर्नेल को प्रक्रिया को रैम से अचानक अलग करने के लिए गणितीय रूप से बाध्य करने के लिए कौन सा निरपेक्ष (absolute) किल सिग्नल इंजेक्ट करना चाहिए?",opts:["SIGTERM (15)","SIGHUP (1)","SIGINT (2)","SIGKILL (9)"],ans:3,exp:"जब कोई प्रशासक 'kill PID' टाइप करता है, तो डिफ़ॉल्ट रूप से SIGTERM (15) भेजा जाता है, जो प्रक्रिया को बंद करने का विनम्र अनुरोध है। यदि प्रक्रिया लॉक है, तो यह इसे अनदेखा कर देती है। तब प्रशासक 'kill -9 PID' का उपयोग करता है। '9' SIGKILL का प्रतिनिधित्व करता है, जिसे कर्नेल रोकता है और एप्लिकेशन को तुरंत समाप्त कर देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Executing the highly structured command 'ls -la' in a Linux terminal generates what specific subset of mathematical data?",opts:["A graphical pie chart of directory disk usage","A brutally detailed 'Long' format listing encompassing exact file permissions, rigid ownership structures, byte sizes, and modification timestamps, explicitly including all 'Hidden' system files prefixed with a dot","A list of purely audio files","A log of all users who have accessed the directory"],ans:1,exp:"The 'ls' command is foundational. The '-l' flag fundamentally alters its mathematical output structure to a 'Long' listing, exposing granular metadata: the rwx permission string, hard link count, owner, group, file size in bytes, and timestamp. The critical '-a' (All) flag aggressively disables the filter that hides files starting with a period (.), exposing hidden configurations like '.bash_history'."},hi:{q:"लिनक्स टर्मिनल में अत्यधिक संरचित कमांड 'ls -la' को निष्पादित करने से गणितीय डेटा का कौन सा विशिष्ट उपसमुच्चय उत्पन्न होता है?",opts:["निर्देशिका डिस्क उपयोग का एक ग्राफिकल पाई चार्ट","सटीक फ़ाइल अनुमतियों, कठोर स्वामित्व संरचनाओं, बाइट आकार और संशोधन टाइमस्टैम्प को शामिल करने वाली एक विस्तृत 'लॉन्ग' (Long) प्रारूप सूची, जिसमें डॉट के साथ शुरू होने वाली सभी 'छिपी' सिस्टम फ़ाइलें स्पष्ट रूप से शामिल हैं","विशुद्ध रूप से ऑडियो फ़ाइलों की एक सूची","निर्देशिका तक पहुंचने वाले सभी उपयोगकर्ताओं का लॉग"],ans:1,exp:"'ls' कमांड मूलभूत है। '-l' ध्वज इसके आउटपुट संरचना को 'लॉन्ग' लिस्टिंग में बदल देता है, जिससे मेटाडेटा (अनुमति स्ट्रिंग, मालिक, समूह, फ़ाइल आकार) उजागर होता है। महत्वपूर्ण '-a' (All) ध्वज उस फ़िल्टर को अक्षम करता है जो बिंदु (.) से शुरू होने वाली फ़ाइलों को छिपाता है।"}},
{type:"mcq",diff:"hard",en:{q:"In the heavily austere 'vi' text editor natively found in Linux, an administrator trapped in Insert mode must execute which exact sequence of keystrokes to mathematically save their edits and forcefully quit the application?",opts:["Ctrl+S followed by Ctrl+Q","Press Escape to revert to Command mode, type a colon (:), type 'wq', and press Enter","Type 'SAVE' and press Enter","Hold Alt and type 'quit'"],ans:1,exp:"The 'vi' editor is notoriously hostile to beginners due to its strict modal architecture. If a user is typing (Insert mode), they must mathematically break out of it by hitting 'Escape' to enter Command mode. They then type the colon ':' to initiate the command-line at the bottom, followed by 'w' (Write the mathematical buffers to the physical disk) and 'q' (Quit the editor), finalized by hitting Enter."},hi:{q:"लिनक्स में पाए जाने वाले 'vi' टेक्स्ट एडिटर में, इंसर्ट (Insert) मोड में फंसे एक प्रशासक को अपने संपादन को सहेजने और एप्लिकेशन को जबरन छोड़ने (Quit) के लिए कीस्ट्रोक्स के किस सटीक क्रम को निष्पादित करना चाहिए?",opts:["Ctrl+S के बाद Ctrl+Q","कमांड मोड पर वापस जाने के लिए Escape दबाएं, कोलन (:) टाइप करें, 'wq' टाइप करें, और Enter दबाएं","'SAVE' टाइप करें और Enter दबाएं","Alt पकड़ें और 'quit' टाइप करें"],ans:1,exp:"'vi' एडिटर शुरुआती लोगों के लिए कठिन है। यदि कोई उपयोगकर्ता टाइप कर रहा है (इंसर्ट मोड), तो उसे कमांड मोड में प्रवेश करने के लिए 'Escape' दबाना होगा। फिर वे 'w' (डिस्क पर लिखने के लिए) और 'q' (छोड़ने के लिए) के बाद नीचे कमांड-लाइन शुरू करने के लिए कोलन ':' टाइप करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"When engineering a DOS Batch Script (.bat), the internal mathematical architecture uses variables like '%1' and '%2'. What do these highly specific variables represent?",opts:["The total physical size of the batch file in bytes","The mathematical error levels returned by the CPU","The specific, sequential Command-Line Arguments (parameters) explicitly passed to the script by the user during execution","The number of lines in the code"],ans:2,exp:"Batch scripts utilize positional parameters to achieve mathematical dynamism. If an administrator writes a script named 'backup.bat' and executes it by typing 'backup.bat C:\\docs D:\\archive', the script mathematically assigns the string 'C:\\docs' to the internal variable %1, and 'D:\\archive' to %2. The internal logic can then aggressively process these dynamically passed variables."},hi:{q:"DOS बैच स्क्रिप्ट (.bat) बनाते समय, आंतरिक गणितीय वास्तुकला '%1' और '%2' जैसे चर (variables) का उपयोग करती है। ये अत्यधिक विशिष्ट चर क्या दर्शाते हैं?",opts:["बाइट में बैच फ़ाइल का कुल भौतिक आकार","सीपीयू द्वारा लौटाए गए गणितीय त्रुटि स्तर","निष्पादन के दौरान उपयोगकर्ता द्वारा स्क्रिप्ट को स्पष्ट रूप से पारित विशिष्ट, अनुक्रमिक कमांड-लाइन तर्क (Command-Line Arguments / पैरामीटर)","कोड में पंक्तियों की संख्या"],ans:2,exp:"बैच स्क्रिप्ट गणितीय गतिशीलता प्राप्त करने के लिए स्थितीय मापदंडों का उपयोग करते हैं। यदि कोई प्रशासक 'backup.bat' नामक स्क्रिप्ट लिखता है और 'backup.bat C:\\docs D:\\archive' टाइप करके इसे निष्पादित करता है, तो स्क्रिप्ट आंतरिक चर %1 को 'C:\\docs' और %2 को 'D:\\archive' असाइन करती है।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced DOS file replication operations, appending the explicit '/E' switch to the XCOPY command forces the algorithm to mathematically execute what unique behavior?",opts:["It mathematically encrypts the copied files securely","It completely erases the source file after duplicating it","It aggressively forces the replication algorithm to recursively copy all nested subdirectories, crucially including directories that are entirely, mathematically empty","It extracts the file from an archive"],ans:2,exp:"XCOPY is a tremendously powerful architectural tool for mirroring disk structures. While the basic '/S' switch commands XCOPY to recursively traverse and duplicate nested subdirectories, it fundamentally ignores mathematically empty folders. Appending the explicit '/E' switch aggressively overrides this, forcing the engine to perfectly replicate the exact structural hierarchy of the source tree, including absolutely barren directories."},hi:{q:"उन्नत DOS फ़ाइल प्रतिकृति संचालन में, XCOPY कमांड में स्पष्ट '/E' स्विच को जोड़ने से एल्गोरिदम गणितीय रूप से क्या अद्वितीय व्यवहार निष्पादित करने के लिए बाध्य होता है?",opts:["यह कॉपी की गई फ़ाइलों को सुरक्षित रूप से एन्क्रिप्ट करता है","यह प्रतिलिपि बनाने के बाद स्रोत फ़ाइल को पूरी तरह से मिटा देता है","यह पुनरावर्ती (recursively) रूप से सभी नेस्टेड उप-निर्देशिकाओं की प्रतिलिपि बनाने के लिए बाध्य करता है, जिसमें पूरी तरह से खाली निर्देशिकाएं भी शामिल हैं","यह एक संग्रह से फ़ाइल निकालता है"],ans:2,exp:"XCOPY डिस्क संरचनाओं को मिरर करने के लिए एक शक्तिशाली उपकरण है। जबकि मूल '/S' स्विच XCOPY को नेस्टेड उप-निर्देशिकाओं की प्रतिलिपि बनाने का आदेश देता है, यह खाली फ़ोल्डरों को अनदेखा कर देता है। स्पष्ट '/E' स्विच इसे ओवरराइड करता है, जिससे इंजन बिल्कुल खाली निर्देशिकाओं सहित स्रोत ट्री की सटीक संरचनात्मक पदानुक्रम की नकल करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In the strict Linux File System Hierarchy Standard, which specific directory mathematically functions as a virtual repository containing special 'Device Nodes', providing the kernel with abstract file pointers to raw physical hardware like hard drives (sda) and terminal interfaces (tty)?",opts:["/usr","/dev","/boot","/mnt"],ans:1,exp:"The '/dev' (Device) directory is a fascinating architectural construct unique to Unix/Linux. True to the 'Everything is a File' paradigm, '/dev' does not contain regular data files. It is strictly populated by virtual 'device nodes' (like /dev/sda for the primary hard disk, or /dev/null). These nodes act as direct mathematical software portals, allowing applications to read/write to physical hardware components as if they were simple text files."},hi:{q:"कठोर लिनक्स फ़ाइल सिस्टम पदानुक्रम मानक (FHS) में, कौन सी विशिष्ट निर्देशिका विशेष 'डिवाइस नोड्स' युक्त आभासी भंडार के रूप में कार्य करती है, जो कर्नेल को हार्ड ड्राइव (sda) जैसे भौतिक हार्डवेयर के लिए फ़ाइल पॉइंटर्स प्रदान करती है?",opts:["/usr","/dev","/boot","/mnt"],ans:1,exp:"'/dev' (डिवाइस) निर्देशिका यूनिक्स/लिनक्स के लिए एक आकर्षक वास्तुकला निर्माण है। 'एवरीथिंग इज़ ए फाइल' प्रतिमान के अनुसार, '/dev' में नियमित डेटा फ़ाइलें नहीं होती हैं। यह आभासी 'डिवाइस नोड्स' (जैसे प्राथमिक हार्ड डिस्क के लिए /dev/sda) से आबाद है। ये नोड्स प्रत्यक्ष सॉफ़्टवेयर पोर्टल्स के रूप में कार्य करते हैं, जिससे एप्लिकेशन भौतिक हार्डवेयर पर पढ़/लिख सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which critical Linux diagnostic command aggressively parses the superblock metadata of mounted filesystems to mathematically output the precise total, used, and available disk space across all active partitions?",opts:["df","du","fdisk","mount"],ans:0,exp:"The 'df' (Disk Free) command is an indispensable administrative tool. Instead of manually tallying file sizes, 'df' interrogates the core filesystem metadata structures (superblocks) of all currently mounted partitions. It instantly outputs a mathematically precise, high-level summary of total block capacity, blocks utilized, available space, and the specific mount points. Appending the '-h' flag converts the raw block data into human-readable Megabytes and Gigabytes."},hi:{q:"कौन सा महत्वपूर्ण लिनक्स डायग्नोस्टिक कमांड सभी सक्रिय विभाजनों में सटीक कुल, उपयोग किए गए और उपलब्ध डिस्क स्थान को गणितीय रूप से आउटपुट करने के लिए माउंटेड फ़ाइल सिस्टम के सुपरब्लॉक मेटाडेटा को आक्रामक रूप से पार्स करता है?",opts:["df","du","fdisk","mount"],ans:0,exp:"'df' (Disk Free) कमांड एक अनिवार्य प्रशासनिक उपकरण है। फ़ाइल आकारों की मैन्युअल रूप से गणना करने के बजाय, 'df' सभी वर्तमान में माउंट किए गए विभाजनों की कोर फ़ाइल सिस्टम मेटाडेटा संरचनाओं से पूछताछ करता है। यह कुल क्षमता, उपयोग किए गए ब्लॉक, उपलब्ध स्थान का एक गणितीय रूप से सटीक सारांश तुरंत आउटपुट करता है।"}},
{type:"mcq",diff:"hard",en:{q:"If a Linux administrator needs to forensically ascertain the precise mathematical amount of volatile RAM currently being utilized by active processes versus cached buffers, which concise terminal command is executed?",opts:["memstat","free","raminfo","top -m"],ans:1,exp:"The 'free' command is the architectural standard for diagnosing volatile memory consumption in Linux. It queries the kernel's internal memory management tables and prints a mathematically exact breakdown. The output rigidly categorizes the total installed RAM, the amount actively consumed by running application threads, and crucially, the massive chunks of memory the kernel intelligently utilizes as temporary disk cache buffers to accelerate standard I/O operations."},hi:{q:"यदि लिनक्स प्रशासक को यह पता लगाने की आवश्यकता है कि वर्तमान में सक्रिय प्रक्रियाओं बनाम कैश्ड बफर द्वारा अस्थिर रैम (volatile RAM) की सटीक गणितीय मात्रा का उपयोग किया जा रहा है, तो कौन सा संक्षिप्त टर्मिनल कमांड निष्पादित किया जाता है?",opts:["memstat","free","raminfo","top -m"],ans:1,exp:"'free' कमांड लिनक्स में अस्थिर मेमोरी (volatile memory) खपत के निदान के लिए मानक है। यह कर्नेल की आंतरिक मेमोरी प्रबंधन तालिकाओं को पूछता है और एक गणितीय रूप से सटीक ब्रेकडाउन प्रिंट करता है। आउटपुट कुल स्थापित रैम, चल रहे एप्लिकेशन द्वारा सक्रिय रूप से उपभोग की जाने वाली मात्रा और अस्थायी डिस्क कैश बफर के रूप में कर्नेल द्वारा उपयोग की जाने वाली मेमोरी को वर्गीकृत करता है।"}},
{type:"mcq",diff:"hard",en:{q:"When a Linux administrator downloads a heavily compressed software archive named 'package.tar.gz', which exact composite sequence of flag parameters must logically accompany the 'tar' command to mathematically decompress and extract the payload into the current directory?",opts:["tar -make","tar -compress","tar -xzf","tar -extract"],ans:2,exp:"The 'tar' (Tape Archive) utility requires precise, syntactical flags. The complex flag string '-xzf' is the absolute standard. The 'x' commands the engine to mathematically Extract the payload. The 'z' explicitly tells the engine to route the stream through the gzip decompression algorithm first (handling the .gz layer). The 'f' specifically declares that the very next text string will be the absolute filename of the archive to target."},hi:{q:"जब कोई लिनक्स एडमिनिस्ट्रेटर 'package.tar.gz' नामक अत्यधिक संपीड़ित सॉफ़्टवेयर संग्रह (archive) डाउनलोड करता है, तो 'tar' कमांड के साथ कौन सा सटीक अनुक्रम होना चाहिए ताकि पेलोड को वर्तमान निर्देशिका में डीकंप्रेस और निकाला (extract) जा सके?",opts:["tar -make","tar -compress","tar -xzf","tar -extract"],ans:2,exp:"'tar' (टेप आर्काइव) उपयोगिता के लिए सटीक, सिंटैक्टिकल झंडों की आवश्यकता होती है। जटिल ध्वज स्ट्रिंग '-xzf' पूर्ण मानक है। 'x' इंजन को पेलोड निकालने (Extract) का आदेश देता है। 'z' स्पष्ट रूप से इंजन को पहले gzip डीकंप्रेसन एल्गोरिदम के माध्यम से स्ट्रीम को रूट करने के लिए कहता है। 'f' घोषणा करता है कि अगली टेक्स्ट स्ट्रिंग लक्ष्य का फ़ाइल नाम होगी।"}},
{type:"mcq",diff:"hard",en:{q:"In the highly esoteric realm of Linux shell redirection, what does the cryptic syntax '>&2' mathematically accomplish at the end of a command?",opts:["It duplicates the file twice","It strictly forces the mathematical routing of Standard Output (stdout/1) directly into the Standard Error (stderr/2) data stream pipeline","It pauses execution for 2 seconds","It runs the command on CPU core number 2"],ans:1,exp:"Unix shells inherently manage three distinct mathematical data streams: Standard Input (0), Standard Output (1), and Standard Error (2). Normally, standard text output and error messages are mixed on the screen. Scripters utilize the arcane '>&2' syntax to aggressively hijack the normal successful output stream (1) and mathematically merge it directly into the separate Error stream pipeline (2). This is vital for cleanly logging errors to a dedicated file independent of normal output."},hi:{q:"लिनक्स शेल रिडायरेक्शन के अत्यधिक गूढ़ दायरे में, एक कमांड के अंत में गुप्त सिंटैक्स '>&2' गणितीय रूप से क्या पूरा करता है?",opts:["यह फ़ाइल की दो बार प्रतिलिपि बनाता है","यह मानक आउटपुट (stdout/1) के गणितीय रूटिंग को सीधे मानक त्रुटि (stderr/2) डेटा स्ट्रीम पाइपलाइन में बाध्य करता है","यह 2 सेकंड के लिए निष्पादन को रोकता है","यह कमांड को CPU कोर नंबर 2 पर चलाता है"],ans:1,exp:"यूनिक्स शेल स्वाभाविक रूप से तीन अलग-अलग गणितीय डेटा स्ट्रीम का प्रबंधन करते हैं: मानक इनपुट (0), मानक आउटपुट (1), और मानक त्रुटि (2)। स्क्रिप्टर सामान्य सफल आउटपुट स्ट्रीम (1) को हाईजैक करने और इसे गणितीय रूप से सीधे अलग त्रुटि स्ट्रीम पाइपलाइन (2) में मर्ज करने के लिए '>&2' सिंटैक्स का उपयोग करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"If a DOS administrator suspects malware is mathematically concealing itself by manipulating file attributes, which highly specific DIR switch parameter forces the explicit rendering of strictly hidden files?",opts:["DIR /H","DIR /A:H","DIR /SHOW","DIR /ALL"],ans:1,exp:"By default, the mathematical execution algorithm of the 'DIR' command actively filters out and ignores any file possessing the Hidden (+h) or System (+s) metadata attributes. To override this architectural filter, the administrator must deploy the '/A' (Attributes) switch, explicitly followed by the modifier ':H'. The strict syntax 'DIR /A:H' radically alters the search query, forcefully ignoring normal files and strictly printing only those actively trying to hide."},hi:{q:"यदि किसी DOS प्रशासक को संदेह है कि मैलवेयर फ़ाइल विशेषताओं में हेरफेर करके खुद को गणितीय रूप से छिपा रहा है, तो कौन सा अत्यधिक विशिष्ट DIR स्विच पैरामीटर कड़ाई से छिपी हुई फ़ाइलों के स्पष्ट प्रतिपादन (rendering) को बाध्य करता है?",opts:["DIR /H","DIR /A:H","DIR /SHOW","DIR /ALL"],ans:1,exp:"डिफ़ॉल्ट रूप से, 'DIR' कमांड का निष्पादन एल्गोरिदम सक्रिय रूप से हिडन (+h) या सिस्टम (+s) मेटाडेटा विशेषताओं वाली किसी भी फ़ाइल को फ़िल्टर करता है और अनदेखा करता है। इस वास्तुशिल्प फ़िल्टर को ओवरराइड करने के लिए, व्यवस्थापक को '/A' (विशेषताएँ) स्विच को तैनात करना होगा, जिसके बाद ':H' संशोधक होगा। 'DIR /A:H' का सिंटैक्स केवल छिपी हुई फ़ाइलों को प्रिंट करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In massive enterprise Linux environments encompassing thousands of users, the 'chgrp' command executes what precise architectural modification?",opts:["It changes the user's login password","It aggressively deletes a specific security group from the entire server","It mathematically reassigns the secondary 'Group' ownership hierarchy of a specific file or directory, altering which collaborative team possesses access rights","It changes the graphical group theme"],ans:2,exp:"Linux permissions are tri-tiered: Owner, Group, and Others. While 'chown' alters the absolute individual Owner, the 'chgrp' (Change Group) command strictly manipulates the secondary ownership tier. By mathematically executing 'chgrp developers project.doc', an administrator instantly reassigns the collaborative ownership bucket of that file to the 'developers' security group, suddenly granting access mathematically to dozens of team members simultaneously."},hi:{q:"हजारों उपयोगकर्ताओं को शामिल करने वाले विशाल एंटरप्राइज़ लिनक्स वातावरण में, 'chgrp' कमांड कौन सा सटीक वास्तुशिल्प संशोधन निष्पादित करता है?",opts:["यह उपयोगकर्ता का लॉगिन पासवर्ड बदलता है","यह संपूर्ण सर्वर से एक विशिष्ट सुरक्षा समूह को आक्रामक रूप से हटा देता है","यह किसी विशिष्ट फ़ाइल या निर्देशिका के द्वितीयक 'समूह' (Group) स्वामित्व पदानुक्रम को गणितीय रूप से पुन: असाइन करता है, यह बदलते हुए कि किस सहयोगी टीम के पास पहुंच अधिकार हैं","यह ग्राफिकल समूह विषय (theme) को बदलता है"],ans:2,exp:"लिनक्स अनुमतियां त्रि-स्तरीय हैं: स्वामी, समूह और अन्य। जबकि 'chown' पूर्ण व्यक्तिगत स्वामी को बदलता है, 'chgrp' (समूह बदलें) कमांड कड़ाई से द्वितीयक स्वामित्व (Group ownership) स्तर में हेरफेर करता है। 'chgrp developers project.doc' निष्पादित करके, एक प्रशासक तुरंत उस फ़ाइल के स्वामित्व को 'डेवलपर्स' सुरक्षा समूह में पुन: असाइन करता है।"}},
{type:"mcq",diff:"hard",en:{q:"To fundamentally prevent a long-running, mathematically complex script from seizing total control of the active Linux terminal interface and locking out the user, which specific operator must be appended strictly at the absolute end of the command string?",opts:["#","@","|","&"],ans:3,exp:"Linux is a pre-emptive multitasking engine. By default, typing a command mathematically locks the active shell process, forcing the interface to freeze and wait until the application officially terminates. Appending the Ampersand symbol ('&') at the precise mathematical end of a command string explicitly instructs the kernel to instantly detach the process and run it silently as a background asynchronous thread, immediately returning the blinking prompt control to the user."},hi:{q:"लंबे समय तक चलने वाली, गणितीय रूप से जटिल स्क्रिप्ट को सक्रिय लिनक्स टर्मिनल इंटरफ़ेस के पूर्ण नियंत्रण को जब्त करने और उपयोगकर्ता को लॉक करने से रोकने के लिए, कमांड स्ट्रिंग के बिल्कुल अंत में कौन सा विशिष्ट ऑपरेटर (operator) जोड़ा जाना चाहिए?",opts:["#","@","|","&"],ans:3,exp:"लिनक्स एक मल्टीटास्किंग इंजन है। डिफ़ॉल्ट रूप से, एक कमांड टाइप करना गणितीय रूप से सक्रिय शेल प्रक्रिया को लॉक कर देता है। कमांड स्ट्रिंग के अंत में एम्परसेंड चिह्न ('&') जोड़ना स्पष्ट रूप से कर्नेल को प्रक्रिया को तुरंत अलग करने और इसे पृष्ठभूमि धागे (background thread) के रूप में चुपचाप चलाने का निर्देश देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Deep within the mathematical architecture of standard Linux file systems (like ext4), what is the explicitly defined purpose of an 'Inode' data structure?",opts:["It stores the actual graphical icons for the desktop","It is the Master Boot Record of the hard drive","It acts as a microscopic, highly rigid database table mathematically storing absolutely all critical metadata regarding a file—including exact disk sector locations, byte size, ownership, and permission matrices—explicitly excluding the actual human-readable filename","It is the software driver for the network card"],ans:2,exp:"The Linux VFS (Virtual File System) radically decouples data from filenames. An 'Inode' (Index Node) is the core mathematical data structure. Every single file physically occupies an Inode. The Inode rigidly stores the heavy metadata: permissions, timestamps, owner IDs, and the exact geometric block addresses on the spinning disk where the raw binary data physically resides. Astonishingly, the human-readable filename is NOT stored in the Inode; filenames are merely string pointers inside a separate directory table that link mathematically back to the corresponding Inode number."},hi:{q:"मानक लिनक्स फ़ाइल सिस्टम (जैसे ext4) की गणितीय वास्तुकला के भीतर गहराई में, 'इनोड' (Inode) डेटा संरचना का स्पष्ट रूप से परिभाषित उद्देश्य क्या है?",opts:["यह डेस्कटॉप के लिए वास्तविक ग्राफिकल आइकन संग्रहीत करता है","यह हार्ड ड्राइव का मास्टर बूट रिकॉर्ड है","यह एक सूक्ष्म, अत्यधिक कठोर डेटाबेस तालिका के रूप में कार्य करता है जो किसी फ़ाइल के संबंध में सभी महत्वपूर्ण मेटाडेटा को गणितीय रूप से संग्रहीत करता है - जिसमें सटीक डिस्क सेक्टर स्थान, आकार, स्वामित्व और अनुमति मैट्रिक्स शामिल हैं - स्पष्ट रूप से वास्तविक मानव-पठनीय फ़ाइल नाम को छोड़कर","यह नेटवर्क कार्ड के लिए सॉफ्टवेयर ड्राइवर है"],ans:2,exp:"लिनक्स VFS फ़ाइलनामों से डेटा को अलग करता है। एक 'इनोड' (इंडेक्स नोड) मुख्य गणितीय डेटा संरचना है। प्रत्येक फ़ाइल भौतिक रूप से एक Inode घेरती है। Inode मेटाडेटा (अनुमतियाँ, टाइमस्टैम्प, स्वामी ID, और डिस्क पर सटीक ब्लॉक पते) संग्रहीत करता है। आश्चर्यजनक रूप से, फ़ाइल का नाम Inode में संग्रहीत नहीं होता है।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced file management, what strictly defines an 'Absolute Path' in the monolithic Linux directory tree?",opts:["A path that navigates using the '..' operator","A path that is encrypted securely","A rigid, mathematically precise directory location string that always explicitly begins at the absolute root slash ('/') and maps downwards traversing every single nested folder node to reach the exact target file","A path containing wildcards"],ans:2,exp:"Navigation strings in Linux exist as either Relative or Absolute. An Absolute Path is a mathematically rigid, undeniable map. It absolutely MUST begin with the leading root slash ('/'). Regardless of where the user is currently working (their Present Working Directory), parsing an Absolute Path (like '/etc/network/interfaces') will mathematically force the system to start parsing from the top-level root layer down, guaranteeing it consistently locates the identical target file."},hi:{q:"उन्नत फ़ाइल प्रबंधन में, अखंड लिनक्स निर्देशिका ट्री में 'पूर्ण पथ' (Absolute Path) को कड़ाई से क्या परिभाषित करता है?",opts:["एक पथ जो '..' ऑपरेटर का उपयोग करके नेविगेट करता है","एक पथ जो सुरक्षित रूप से एन्क्रिप्ट किया गया है","एक कठोर, गणितीय रूप से सटीक निर्देशिका स्थान स्ट्रिंग जो हमेशा स्पष्ट रूप से पूर्ण रूट स्लैश ('/') से शुरू होती है और सटीक लक्ष्य फ़ाइल तक पहुंचने के लिए हर एक नेस्टेड फ़ोल्डर नोड को पार करते हुए नीचे की ओर मैप करती है","वाइल्डकार्ड युक्त एक पथ"],ans:2,exp:"लिनक्स में नेविगेशन स्ट्रिंग्स रिलेटिव (Relative) या एब्सोल्यूट (Absolute) के रूप में मौजूद हैं। एक एब्सोल्यूट पाथ (पूर्ण पथ) एक गणितीय रूप से कठोर नक्शा है। यह अनिवार्य रूप से अग्रणी रूट स्लैश ('/') से शुरू होना चाहिए। यह सिस्टम को शीर्ष-स्तरीय रूट परत से पार्स करना शुरू करने के लिए बाध्य करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Conversely, what constitutes a 'Relative Path' in Linux architectural navigation?",opts:["A path that relies exclusively on the user's Present Working Directory (PWD) as the mathematical starting coordinate, heavily utilizing dots ('.' and '..') to move dynamically up or down the localized nested structure without referencing the absolute root","A path explicitly starting with 'C:'","A path used only for internet URLs","A path representing deleted files"],ans:0,exp:"A Relative Path relies entirely on mathematical context. It explicitly omits the leading root slash ('/'). If a user is currently sitting deep inside '/var/log', typing the relative command 'cd ../www' forces the kernel to mathematically calculate the route starting from the immediate localized position—jumping up one parent node ('..') to '/var', and then diving down into the adjacent 'www' bucket, entirely blind to the overarching root structure."},hi:{q:"इसके विपरीत, लिनक्स आर्किटेक्चरल नेविगेशन में 'रिलेटिव पाथ' (Relative Path) का क्या अर्थ है?",opts:["एक ऐसा पथ जो विशेष रूप से उपयोगकर्ता की वर्तमान कार्यशील निर्देशिका (PWD) पर गणितीय प्रारंभिक समन्वय के रूप में निर्भर करता है, पूर्ण रूट (root) का संदर्भ दिए बिना स्थानीयकृत नेस्टेड संरचना को गतिशील रूप से ऊपर या नीचे ले जाने के लिए डॉट्स ('.' और '..') का भारी उपयोग करता है","स्पष्ट रूप से 'C:' से शुरू होने वाला पथ","केवल इंटरनेट URL के लिए उपयोग किया जाने वाला पथ","हटाए गए फ़ाइलों का प्रतिनिधित्व करने वाला पथ"],ans:0,exp:"एक सापेक्ष पथ (Relative Path) पूरी तरह से गणितीय संदर्भ पर निर्भर करता है। यह स्पष्ट रूप से अग्रणी रूट स्लैश ('/') को छोड़ देता है। यदि कोई उपयोगकर्ता वर्तमान में '/var/log' के अंदर बैठा है, तो सापेक्ष कमांड 'cd ../www' टाइप करने से कर्नेल को तत्काल स्थानीयकृत स्थिति से शुरू होने वाले मार्ग की गणना करने के लिए मजबूर किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which highly advanced, incredibly robust Linux utility is mathematically engineered to aggressively traverse entire directory trees, locate files matching immensely complex metadata parameters (like exact byte sizes, modification timestamps, or complex regex names), and execute subsequent commands directly upon the discovered targets?",opts:["search","locate","whereis","find"],ans:3,exp:"The 'find' command is an administrative powerhouse. While 'locate' relies on a pre-built static database index, 'find' performs a brutal, live mathematical crawl of the active filesystem hierarchy. Administrators can engineer complex queries like 'find /var -type f -name \"*.log\" -size +50M -mtime -7 -exec rm {} \\;', which actively hunts down log files larger than 50MB modified in the last week and instantly pipes them into the 'rm' destruction algorithm."},hi:{q:"संपूर्ण निर्देशिका ट्री को आक्रामक रूप से पार करने, अत्यधिक जटिल मेटाडेटा मापदंडों (जैसे सटीक बाइट आकार, संशोधन टाइमस्टैम्प) से मेल खाने वाली फ़ाइलों का पता लगाने और खोजे गए लक्ष्यों पर सीधे बाद के आदेशों को निष्पादित करने के लिए गणितीय रूप से किस अत्यधिक उन्नत लिनक्स उपयोगिता को इंजीनियर किया गया है?",opts:["search","locate","whereis","find"],ans:3,exp:"'find' कमांड एक प्रशासनिक पावरहाउस है। जबकि 'locate' पूर्व-निर्मित डेटाबेस इंडेक्स पर निर्भर करता है, 'find' सक्रिय फ़ाइल सिस्टम पदानुक्रम का एक लाइव गणितीय क्रॉल करता है। प्रशासक इसके द्वारा आकार, समय और नाम के आधार पर जटिल रूप से फ़ाइलों को खोज सकते हैं और उन पर कमांड चला सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"When executing the powerful 'grep' utility in Linux text processing, explicitly appending the '-i' flag mathematically forces the parsing engine to perform what specific behavioral modification?",opts:["It forces the engine to Ignore the command completely","It forces the mathematical regex parsing engine to become completely Case-Insensitive, treating uppercase 'ERROR' and lowercase 'error' as completely identical string matches","It forces the engine to Insert new lines into the text","It forcefully Ignites a background process"],ans:1,exp:"The Linux shell is notoriously, mathematically case-sensitive by default. 'Grep' relies on exact byte-for-byte ASCII matches. Appending the '-i' (Ignore case) flag alters the underlying comparison algorithm. The mathematical engine is forced to dynamically normalize all scanned text strings and search queries to a uniform case before comparison, ensuring that 'SystemFault', 'systemfault', and 'SYSTEMFAULT' all trigger a positive, successful mathematical match."},hi:{q:"लिनक्स टेक्स्ट प्रोसेसिंग में शक्तिशाली 'grep' उपयोगिता को निष्पादित करते समय, '-i' ध्वज (flag) को स्पष्ट रूप से जोड़ने से पार्सिंग इंजन को कौन सा विशिष्ट व्यवहार संशोधन करने के लिए गणितीय रूप से बाध्य किया जाता है?",opts:["यह इंजन को कमांड को पूरी तरह से अनदेखा करने के लिए बाध्य करता है","यह गणितीय रेगेक्स पार्सिंग इंजन को पूरी तरह से केस-इन्सेंसिटिव (Case-Insensitive) होने के लिए बाध्य करता है, अपरकेस 'ERROR' और लोअरकेस 'error' को पूरी तरह से समान स्ट्रिंग के रूप में मानता है","यह इंजन को टेक्स्ट में नई लाइनें सम्मिलित करने के लिए बाध्य करता है","यह बलपूर्वक एक पृष्ठभूमि प्रक्रिया को प्रज्वलित करता है"],ans:1,exp:"लिनक्स शेल डिफ़ॉल्ट रूप से केस-सेंसिटिव है। '-i' (Ignore case) ध्वज को जोड़ने से तुलना एल्गोरिथ्म बदल जाता है। गणितीय इंजन सभी स्कैन किए गए टेक्स्ट स्ट्रिंग्स और खोज प्रश्नों को तुलना से पहले एक समान केस में गतिशील रूप से सामान्य करने के लिए मजबूर होता है, यह सुनिश्चित करता है कि 'ERROR' और 'error' दोनों एक सफल मैच ट्रिगर करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced DOS Batch scripting automation, what is the architectural significance and mathematical function of the internal %ERRORLEVEL% environment variable?",opts:["It tracks the temperature of the CPU","It mathematically stores an integer (usually 0 for success, or >0 for failure) directly passed back from the kernel representing the exact exit status of the previously executed command, allowing scripts to implement conditional branching logic","It generates random error messages","It tracks the number of typos the user makes"],ans:1,exp:"The %ERRORLEVEL% variable is the foundation of conditional logic in DOS scripts. When an external executable or core command completes its task, it pushes a raw integer back to the shell architecture. By standard convention, a flawless execution returns mathematically '0'. If a file is locked or a drive fails, the command returns a non-zero integer. Advanced batch scripts actively probe this variable using 'IF ERRORLEVEL 1 GOTO FAIL' statements to intelligently divert execution flow based on success or failure."},hi:{q:"उन्नत DOS बैच (Batch) स्क्रिप्टिंग स्वचालन में, आंतरिक %ERRORLEVEL% पर्यावरण चर (environment variable) का वास्तुशिल्प महत्व और गणितीय कार्य क्या है?",opts:["यह सीपीयू के तापमान को ट्रैक करता है","यह गणितीय रूप से कर्नेल से सीधे वापस भेजे गए एक पूर्णांक (आमतौर पर सफलता के लिए 0, या विफलता के लिए >0) को संग्रहीत करता है जो पहले निष्पादित कमांड की सटीक निकास स्थिति (exit status) का प्रतिनिधित्व करता है, जिससे स्क्रिप्ट सशर्त (conditional) तर्क को लागू कर सकती हैं","यह यादृच्छिक त्रुटि संदेश उत्पन्न करता है","यह उपयोगकर्ता द्वारा की जाने वाली टाइपो की संख्या को ट्रैक करता है"],ans:1,exp:"%ERRORLEVEL% चर DOS स्क्रिप्ट में सशर्त तर्क की नींव है। जब कोई कमांड अपना कार्य पूरा करता है, तो वह एक पूर्णांक शेल में वापस धकेलता है। एक दोषरहित निष्पादन गणितीय रूप से '0' लौटाता है। यदि कमांड विफल हो जाता है, तो यह गैर-शून्य पूर्णांक लौटाता है। स्क्रिप्ट इसका उपयोग त्रुटियों को संभालने के लिए करती हैं।"}},
{type:"mcq",diff:"hard",en:{q:"If an administrator needs to rapidly extract and display strictly the absolute final 10 lines of a massively bloated, multi-gigabyte log file without crashing the RAM, which hyper-efficient Linux command is utilized?",opts:["head","cat","tail","less"],ans:2,exp:"The 'tail' command is mathematically optimized for processing colossal text files. Unlike 'cat', which brutally attempts to dump the entire multi-gigabyte file payload into standard output (often bottlenecking the console buffer), 'tail' employs a highly efficient mathematical seek algorithm. It drops directly to the physical end of the file pointer on the disk, reads backwards, and surgically extracts and prints only the final 10 trailing lines (by default) almost instantaneously."},hi:{q:"यदि किसी प्रशासक को RAM को क्रैश किए बिना एक विशाल, मल्टी-गीगाबाइट लॉग फ़ाइल के कड़ाई से अंतिम 10 पंक्तियों को तेजी से निकालने और प्रदर्शित करने की आवश्यकता है, तो किस अति-कुशल लिनक्स कमांड का उपयोग किया जाता है?",opts:["head","cat","tail","less"],ans:2,exp:"'tail' कमांड विशाल टेक्स्ट फ़ाइलों को संसाधित करने के लिए गणितीय रूप से अनुकूलित है। 'cat' के विपरीत, जो पूरी फ़ाइल को आउटपुट में डंप करने का प्रयास करता है, 'tail' एक कुशल गणितीय खोज एल्गोरिथ्म को नियुक्त करता है। यह सीधे डिस्क पर फ़ाइल पॉइंटर के भौतिक अंत तक जाता है और लगभग तुरंत केवल अंतिम 10 लाइनों को निकालता और प्रिंट करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Conversely, which specific Linux command mathematically executes an optimized seek algorithm to surgically extract and display strictly the absolute first 10 lines of a specified text file?",opts:["top","front","first","head"],ans:3,exp:"The 'head' command serves as the precise architectural mirror to 'tail'. It reads the data stream from the absolute mathematical beginning of the file pointer and stops completely after parsing exactly 10 line break characters (\\n). This allows the OS to process only a microscopic fraction of a massive file, making it exceptionally fast for inspecting headers, configuration file comments, or data schemas without wasting processor cycles."},hi:{q:"इसके विपरीत, कौन सा विशिष्ट लिनक्स कमांड एक निर्दिष्ट टेक्स्ट फ़ाइल के कड़ाई से पहले 10 पंक्तियों को शल्य चिकित्सा (surgically) निकालने और प्रदर्शित करने के लिए एक अनुकूलित खोज एल्गोरिदम को गणितीय रूप से निष्पादित करता है?",opts:["top","front","first","head"],ans:3,exp:"'head' कमांड 'tail' के सटीक वास्तुशिल्प दर्पण के रूप में कार्य करता है। यह फ़ाइल पॉइंटर के पूर्ण गणितीय शुरुआत से डेटा स्ट्रीम पढ़ता है और ठीक 10 लाइन ब्रेक वर्णों (\\n) को पार्स करने के बाद पूरी तरह से रुक जाता है। यह विशाल फ़ाइल के केवल एक सूक्ष्म अंश को संसाधित करने की अनुमति देता है।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced Linux filesystem architecture, what mathematically defines a 'Symbolic Link' (symlink) created using the 'ln -s' command?",opts:["It is an exact, byte-for-byte duplicated clone of the original file","It is a rigid graphical icon","It is an empty placeholder file that mathematically contains only a directional string pointer pointing the kernel to the absolute or relative path of the actual target file or directory located elsewhere on the disk","It is an encrypted version of the file"],ans:2,exp:"A Symbolic Link (symlink) is deeply analogous to a Windows 'Shortcut', but operates directly at the kernel file system layer. The symlink file physically contains zero actual data payload; its mathematical structure strictly houses an ASCII text string denoting the absolute or relative path to the true target inode. If the original target file is physically deleted, the symlink mathematically breaks, becoming a 'dangling link' that points to a void."},hi:{q:"उन्नत लिनक्स फ़ाइल सिस्टम वास्तुकला में, 'ln -s' कमांड का उपयोग करके बनाए गए 'सिंबोलिक लिंक' (symlink) को गणितीय रूप से क्या परिभाषित करता है?",opts:["यह मूल फ़ाइल का एक सटीक, बाइट-फ़ॉर-बाइट डुप्लिकेट क्लोन है","यह एक कठोर ग्राफिकल आइकन है","यह एक खाली प्लेसहोल्डर फ़ाइल है जिसमें गणितीय रूप से केवल एक दिशात्मक स्ट्रिंग पॉइंटर होता है जो कर्नेल को डिस्क पर कहीं और स्थित वास्तविक लक्ष्य फ़ाइल या निर्देशिका के पूर्ण या सापेक्ष पथ की ओर इशारा करता है","यह फ़ाइल का एन्क्रिप्टेड संस्करण है"],ans:2,exp:"एक सिंबोलिक लिंक (symlink) काफी हद तक विंडोज 'शॉर्टकट' के समान है, लेकिन सीधे कर्नेल फ़ाइल सिस्टम परत पर काम करता है। सिम्लिंक फ़ाइल में भौतिक रूप से शून्य वास्तविक डेटा पेलोड होता है; इसमें केवल एक पथ (path) होता है जो वास्तविक लक्ष्य इनोड (inode) को दर्शाता है। यदि मूल लक्ष्य फ़ाइल हटा दी जाती है, तो सिम्लिंक टूट जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which esoteric Linux terminal command aggregates massive amounts of deep architectural data, actively querying the compiled kernel to mathematically print the exact OS name, network node hostname, precise kernel release version, compiled processor architecture (e.g., x86_64), and the specific GNU compilation date?",opts:["sysinfo","kernelstat","os-release","uname -a"],ans:3,exp:"The 'uname' (Unix Name) command is a core diagnostic utility. By aggressively appending the '-a' (All) flag, the administrator forces the utility to systematically execute multiple internal system calls. It interrogates the raw kernel memory blocks and algorithmically outputs a highly dense string containing the entire mathematical and structural identity of the running machine environment, heavily utilized in automated deployment scripts to verify server architecture."},hi:{q:"कौन सा लिनक्स टर्मिनल कमांड गहरी वास्तुशिल्प डेटा की भारी मात्रा को एकत्रित करता है, सक्रिय रूप से संकलित कर्नेल से सटीक OS नाम, नेटवर्क नोड होस्टनाम, कर्नेल रिलीज़ संस्करण, संकलित प्रोसेसर आर्किटेक्चर (उदा. x86_64), और विशिष्ट GNU संकलन तिथि प्रिंट करने के लिए पूछताछ करता है?",opts:["sysinfo","kernelstat","os-release","uname -a"],ans:3,exp:"'uname' (Unix Name) कमांड एक कोर डायग्नोस्टिक उपयोगिता है। '-a' (All) ध्वज को जोड़कर, प्रशासक उपयोगिता को कई आंतरिक सिस्टम कॉल निष्पादित करने के लिए बाध्य करता है। यह चल रहे मशीन वातावरण की संपूर्ण गणितीय और संरचनात्मक पहचान वाली एक अत्यधिक घनी स्ट्रिंग आउटपुट करता है।"}},
{type:"tf",diff:"hard",en:{q:"In the highly rigid mathematical execution flow of MS-DOS, the fundamental 'Internal Commands' (like DIR, COPY, DEL) do not exist as independent executable files on the hard drive; they are physically baked directly into the binary code of 'COMMAND.COM' and loaded entirely into RAM during the boot sequence.",opts:["True","False"],ans:0,exp:"This is definitively True. The DOS architecture achieves extreme mathematical efficiency by embedding the absolute most frequently utilized commands directly within the core shell interpreter ('COMMAND.COM'). Because these internal commands are persistently resident within the high-speed volatile RAM, the CPU can parse and execute them instantaneously, completely bypassing the massive latency of initiating a mechanical hard drive seek to load an external binary file."},hi:{q:"MS-DOS के अत्यधिक कठोर गणितीय निष्पादन प्रवाह में, मौलिक 'आंतरिक कमांड' (जैसे DIR, COPY, DEL) हार्ड ड्राइव पर स्वतंत्र निष्पादन योग्य फ़ाइलों के रूप में मौजूद नहीं हैं; वे भौतिक रूप से सीधे 'COMMAND.COM' के बाइनरी कोड में बेक किए गए हैं और बूट अनुक्रम के दौरान पूरी तरह से RAM में लोड किए गए हैं।",opts:["सही","गलत"],ans:0,exp:"यह निश्चित रूप से सत्य है। DOS वास्तुकला कोर शेल इंटरप्रेटर ('COMMAND.COM') के भीतर सीधे सबसे अधिक उपयोग किए जाने वाले आदेशों को एम्बेड करके अत्यधिक गणितीय दक्षता प्राप्त करती है। चूंकि ये आंतरिक कमांड हाई-स्पीड अस्थिर RAM के भीतर लगातार मौजूद रहते हैं, इसलिए CPU बाहरी बाइनरी फ़ाइल को लोड करने में लगने वाले समय को पूरी तरह से दरकिनार करते हुए, उन्हें तुरंत पार्स और निष्पादित कर सकता है।"}},
{type:"tf",diff:"hard",en:{q:"Under the absolute rules of the Linux permission matrix, forcefully assigning a file the octal permission code '777' guarantees that mathematically, only the 'root' superuser possesses the overarching authority to Read, Write, and Execute that specific file payload.",opts:["True","False"],ans:1,exp:"This is catastrophically False. In the octal mathematical permission matrix, a '7' (4+2+1) grants absolute Read, Write, and Execute power. The syntax 'chmod 777' assigns this unrestrained '7' power simultaneously to the Owner, the Group, and mathematically to absolutely 'Others' (Every single user globally logged into the system). It completely demolishes all security boundaries, essentially opening the file to be maliciously altered or executed by any unauthenticated guest account."},hi:{q:"लिनक्स अनुमति मैट्रिक्स के पूर्ण नियमों के तहत, किसी फ़ाइल को बलपूर्वक ऑक्टल अनुमति कोड '777' असाइन करना यह गारंटी देता है कि गणितीय रूप से, केवल 'रूट' (root) सुपरयूज़र के पास उस विशिष्ट फ़ाइल पेलोड को पढ़ने, लिखने और निष्पादित करने का व्यापक अधिकार है।",opts:["सही","गलत"],ans:1,exp:"यह विनाशकारी रूप से गलत है। ऑक्टल गणितीय अनुमति मैट्रिक्स में, '7' (4+2+1) पूर्ण रीड, राइट और एक्सीक्यूट (निष्पादन) शक्ति प्रदान करता है। 'chmod 777' सिंटैक्स यह अप्रतिबंधित शक्ति एक साथ स्वामी (Owner), समूह (Group), और 'अन्य' (सिस्टम में लॉग इन हर एक उपयोगकर्ता) को असाइन करता है। यह सभी सुरक्षा सीमाओं को पूरी तरह से ध्वस्त कर देता है।"}}
,
{"type":"mcq","diff":"medium","en":{"q":"In Linux, which command is used to display the content of a text file directly on the terminal screen without opening any editor?","opts":["show","cat","read","print"],"ans":1,"exp":"The 'cat' (Concatenate) command is used to display the contents of a file directly on the terminal. It reads the file sequentially and outputs the entire content to standard output. It can also be used to concatenate multiple files together or create new files using redirection. For example, 'cat filename.txt' will print the file's content on the screen instantly."},"hi":{"q":"Linux में, किस कमांड का उपयोग किसी टेक्स्ट फ़ाइल की सामग्री को बिना किसी एडिटर में खोले सीधे टर्मिनल स्क्रीन पर प्रदर्शित करने के लिए किया जाता है?","opts":["show","cat","read","print"],"ans":1,"exp":"'cat' (Concatenate) कमांड का उपयोग किसी फ़ाइल की सामग्री को सीधे टर्मिनल पर प्रदर्शित करने के लिए किया जाता है। यह फ़ाइल को क्रमिक रूप से पढ़ता है और पूरी सामग्री को स्टैंडर्ड आउटपुट पर भेजता है। इसका उपयोग कई फ़ाइलों को एक साथ जोड़ने या रीडायरेक्शन का उपयोग करके नई फ़ाइलें बनाने के लिए भी किया जा सकता है।"}},
{"type":"mcq","diff":"medium","en":{"q":"Which DOS command is used to display or set the current date in the system, and also prompts the user to enter a new date if needed?","opts":["TIME","DATE","CLOCK","CAL"],"ans":1,"exp":"The 'DATE' command in DOS is used to display the current system date and also allows the user to change it. When executed, it shows the current date and then prompts 'Enter new date (mm-dd-yy):'. If the user just presses Enter without typing anything, the date remains unchanged. Similarly, the 'TIME' command is used for system time management."},"hi":{"q":"कौन सा DOS कमांड सिस्टम में वर्तमान दिनांक (date) प्रदर्शित करने या सेट करने के लिए उपयोग किया जाता है?","opts":["TIME","DATE","CLOCK","CAL"],"ans":1,"exp":"DOS में 'DATE' कमांड का उपयोग वर्तमान सिस्टम दिनांक प्रदर्शित करने और उसे बदलने के लिए किया जाता है। जब इसे निष्पादित किया जाता है तो यह वर्तमान दिनांक दिखाता है और फिर नई तारीख दर्ज करने के लिए प्रेरित करता है। यदि उपयोगकर्ता बिना कुछ टाइप किए Enter दबाता है तो दिनांक अपरिवर्तित रहती है।"}},
{"type":"mcq","diff":"medium","en":{"q":"In Linux, which command is used to count the total number of lines, words, and characters in a given text file?","opts":["count","lc","wc","tally"],"ans":2,"exp":"The 'wc' (Word Count) command in Linux is a powerful text processing utility used to count the number of lines, words, and bytes/characters in a file. When executed as 'wc filename', it outputs three numbers: line count, word count, and byte count. Specific flags include '-l' for lines only, '-w' for words only, and '-c' for bytes/characters only. It is widely used in shell scripting and data processing."},"hi":{"q":"Linux में, किसी दी गई टेक्स्ट फ़ाइल में पंक्तियों, शब्दों और वर्णों की कुल संख्या गिनने के लिए किस कमांड का उपयोग किया जाता है?","opts":["count","lc","wc","tally"],"ans":2,"exp":"Linux में 'wc' (Word Count) कमांड एक शक्तिशाली टेक्स्ट प्रोसेसिंग उपयोगिता है। 'wc filename' निष्पादित होने पर तीन संख्याएं आउटपुट करता है: पंक्ति गणना, शब्द गणना और बाइट गणना। '-l' केवल पंक्तियों के लिए, '-w' केवल शब्दों के लिए, और '-c' केवल बाइट्स के लिए उपयोग किया जाता है।"}},
{"type":"mcq","diff":"medium","en":{"q":"Which DOS command is used to display the contents of a long text file one screen at a time, pausing for user input before scrolling further?","opts":["DIR /P","TYPE","MORE","READ"],"ans":2,"exp":"The 'MORE' command in DOS is an external filter command used to display the output of a file or command one screen at a time. When the screen fills up, it pauses and displays '-- More --' at the bottom, waiting for the user to press a key to continue. It is commonly used with the pipe operator, e.g., 'DIR | MORE' or 'TYPE file.txt | MORE', to prevent output from scrolling past too quickly."},"hi":{"q":"कौन सा DOS कमांड एक लंबी टेक्स्ट फ़ाइल की सामग्री को एक बार में एक स्क्रीन प्रदर्शित करने के लिए उपयोग किया जाता है?","opts":["DIR /P","TYPE","MORE","READ"],"ans":2,"exp":"DOS में 'MORE' कमांड एक बाहरी फ़िल्टर कमांड है जो किसी फ़ाइल के आउटपुट को एक बार में एक स्क्रीन प्रदर्शित करता है। जब स्क्रीन भर जाती है तो यह रुकता है और '-- More --' प्रदर्शित करता है। इसे 'DIR | MORE' या 'TYPE file.txt | MORE' के रूप में पाइप ऑपरेटर के साथ उपयोग किया जाता है।"}},
{"type":"mcq","diff":"hard","en":{"q":"In advanced Linux shell scripting, when a system administrator executes the compound command 'find /var/log -name \"*.log\" -mtime +30 -exec rm -f {} \\;', what precise filesystem operation does this entire command pipeline perform?","opts":["It searches only the current directory for .log files modified today and moves them to /tmp","It recursively traverses the entire /var/log directory tree, identifies every .log file whose last modification timestamp is strictly greater than 30 days old, and then sequentially executes the rm -f delete operation on each matched file","It compresses all log files older than 30 days into a .tar.gz archive","It changes the ownership of all .log files in /var/log to the root user"],"ans":1,"exp":"This compound command performs a multi-stage filesystem operation. The 'find' utility recursively traverses /var/log. The '-name \"*.log\"' flag filters only .log files. The '-mtime +30' flag selects files whose last modification timestamp is older than 30 days. Finally, '-exec rm -f {} \\;' passes each matched file to 'rm -f' which forcefully deletes it without prompting. This is a standard automated log cleanup pattern used in production Linux servers."},"hi":{"q":"उन्नत Linux शेल स्क्रिप्टिंग में, कमांड 'find /var/log -name \"*.log\" -mtime +30 -exec rm -f {} \\;' क्या फ़ाइल सिस्टम ऑपरेशन करती है?","opts":["यह केवल वर्तमान निर्देशिका में आज संशोधित .log फ़ाइलों को खोजती है","यह पूरे /var/log निर्देशिका ट्री को पुनरावर्ती रूप से पार करती है, 30 दिनों से अधिक पुरानी प्रत्येक .log फ़ाइल की पहचान करती है, और फिर प्रत्येक मिलान फ़ाइल पर rm -f डिलीट ऑपरेशन निष्पादित करती है","यह 30 दिनों से अधिक पुरानी सभी log फ़ाइलों को .tar.gz आर्काइव में संपीड़ित करती है","यह /var/log में सभी .log फ़ाइलों का स्वामित्व root उपयोगकर्ता को बदलती है"],"ans":1,"exp":"यह कंपाउंड कमांड बहु-चरणीय ऑपरेशन करती है। 'find' /var/log को पुनरावर्ती रूप से पार करती है। '-name \"*.log\"' केवल .log फ़ाइलों को फ़िल्टर करता है। '-mtime +30' 30 दिनों से पुरानी फ़ाइलें चुनता है। '-exec rm -f {} \\;' प्रत्येक मिलान फ़ाइल को बिना प्रॉम्प्ट के बलपूर्वक हटाता है। यह production Linux servers में उपयोग होने वाला मानक automated log cleanup pattern है।"}}
];